UPDATE words SET example_en_2 = 'She covered her mouth when she laughed.', example_ko_2 = '그녀는 웃을 때 입을 가렸어요.', example_en_3 = 'He rinsed his mouth with water after brushing his teeth.', example_ko_3 = '그는 이를 닦은 후 물로 입을 헹궜어요.', example_en_4 = 'The dentist asked her to keep her mouth open.', example_ko_4 = '치과 의사가 그녀에게 입을 벌리고 있으라고 했어요.', example_en_5 = 'Do not talk with your mouth full of food.', example_ko_5 = '음식을 입에 가득 넣고 말하지 마세요.' WHERE id = 'w_body_A1_05';
UPDATE words SET example_en_2 = 'She brushed her teeth twice a day.', example_ko_2 = '그녀는 하루에 두 번 이를 닦았어요.', example_en_3 = 'The child was afraid of losing her first tooth.', example_ko_3 = '그 아이는 첫 번째 이가 빠지는 것이 두려웠어요.', example_en_4 = 'A healthy diet helps keep your teeth strong.', example_ko_4 = '건강한 식단은 치아를 튼튼하게 유지하는 데 도움이 돼요.', example_en_5 = 'The dentist cleaned each tooth carefully.', example_ko_5 = '치과 의사가 각 치아를 꼼꼼하게 세척했어요.' WHERE id = 'w_body_A1_06';
