UPDATE words SET example_en_2 = 'She folded her arms across her chest.', example_ko_2 = '그녀는 팔짱을 끼고 가슴 앞에 놓았어요.', example_en_3 = 'He broke his arm while playing sports.', example_ko_3 = '그는 운동 중에 팔이 부러졌어요.', example_en_4 = 'She held the umbrella under her arm.', example_ko_4 = '그녀는 우산을 팔 아래에 끼고 있었어요.', example_en_5 = 'The swimmer moved each arm in a strong stroke.', example_ko_5 = '수영 선수는 강한 스트로크로 각 팔을 움직였어요.' WHERE id = 'w_body_A1_10';
