UPDATE words SET example_en_2 = 'She feels healthiest when she exercises regularly.', example_ko_2 = '그녀는 규칙적으로 운동할 때 가장 건강하다고 느껴요.', example_en_3 = 'A healthy breakfast gives you energy for the day.', example_ko_3 = '건강한 아침식사는 하루 동안 에너지를 줘요.', example_en_4 = 'He looks healthy despite being over eighty.', example_ko_4 = '그는 여든이 넘었음에도 건강해 보여요.', example_en_5 = 'Getting enough sleep is key to staying healthy.', example_ko_5 = '충분한 수면을 취하는 것은 건강을 유지하는 핵심이에요.' WHERE id = 'w_body_A2_35';

