UPDATE words SET example_en_2 = 'She attended a workshop on improving posture at work.', example_ko_2 = '그녀는 직장에서 자세 개선에 관한 워크숍에 참석했어요.', example_en_3 = 'His posture improved after a few weeks of yoga.', example_ko_3 = '몇 주간의 요가 후에 그의 자세가 향상됐어요.', example_en_4 = 'Children often develop bad posture from looking at phones.', example_ko_4 = '아이들은 종종 휴대폰을 들여다보다가 나쁜 자세가 생겨요.', example_en_5 = 'A physiotherapist advised her to work on her posture.', example_ko_5 = '물리치료사가 그녀에게 자세를 개선하도록 조언했어요.' WHERE id = 'w_body_B1_01';
UPDATE words SET example_en_2 = 'She stretched every morning to maintain her flexibility.', example_ko_2 = '그녀는 유연성을 유지하기 위해 매일 아침 스트레칭했어요.', example_en_3 = 'The gymnast showed incredible flexibility in her routine.', example_ko_3 = '체조 선수는 루틴에서 놀라운 유연성을 보여줬어요.', example_en_4 = 'Flexibility decreases if you don''t exercise regularly.', example_ko_4 = '규칙적으로 운동하지 않으면 유연성이 떨어져요.', example_en_5 = 'She appreciated the flexibility of the new workout plan.', example_ko_5 = '그녀는 새로운 운동 계획의 유연성을 높이 평가했어요.' WHERE id = 'w_body_B1_02';
UPDATE words SET example_en_2 = 'Good hand-eye coordination is needed for tennis.', example_ko_2 = '테니스에는 좋은 손-눈 협응력이 필요해요.', example_en_3 = 'The coach worked with the players on their coordination.', example_ko_3 = '코치는 선수들의 협응력 향상을 위해 함께 훈련했어요.', example_en_4 = 'Children develop coordination by playing physical games.', example_ko_4 = '아이들은 신체 게임을 하면서 협응력을 키워요.', example_en_5 = 'Poor coordination can make daily tasks more difficult.', example_ko_5 = '협응력이 부족하면 일상적인 업무가 더 어려워질 수 있어요.' WHERE id = 'w_body_B1_03';
UPDATE words SET example_en_2 = 'She lost her balance and grabbed the rail.', example_ko_2 = '그녀는 균형을 잃고 난간을 잡았어요.', example_en_3 = 'He trained his balance by standing on a wobble board.', example_ko_3 = '그는 흔들림 판 위에 서서 균형 감각을 훈련했어요.', example_en_4 = 'A good sense of balance helps prevent falls in older adults.', example_ko_4 = '균형 감각이 좋으면 노인의 낙상 예방에 도움이 돼요.', example_en_5 = 'She tried to maintain her balance on the moving bus.', example_ko_5 = '그녀는 움직이는 버스에서 균형을 유지하려고 했어요.' WHERE id = 'w_body_B1_04';
UPDATE words SET example_en_2 = 'She had to sit out the match because of her injury.', example_ko_2 = '그녀는 부상 때문에 경기를 빠져야 했어요.', example_en_3 = 'A minor injury can become serious if left untreated.', example_ko_3 = '가벼운 부상도 치료하지 않으면 심각해질 수 있어요.', example_en_4 = 'He wore a knee brace to protect his old injury.', example_ko_4 = '그는 오래된 부상 부위를 보호하기 위해 무릎 보호대를 착용했어요.', example_en_5 = 'Stretching before exercise can reduce the risk of injury.', example_ko_5 = '운동 전 스트레칭은 부상 위험을 줄일 수 있어요.' WHERE id = 'w_body_B1_05';
UPDATE words SET example_en_2 = 'He was embarrassed about the scar on his face.', example_ko_2 = '그는 얼굴의 흉터가 부끄러웠어요.', example_en_3 = 'The scar faded over several years.', example_ko_3 = '흉터는 몇 년에 걸쳐 옅어졌어요.', example_en_4 = 'She applied a cream daily to reduce the appearance of the scar.', example_ko_4 = '그녀는 흉터를 줄이기 위해 매일 크림을 발랐어요.', example_en_5 = 'He wore the scar as a reminder of his difficult journey.', example_ko_5 = '그는 그 흉터를 힘든 여정의 기억으로 간직했어요.' WHERE id = 'w_body_B1_06';
UPDATE words SET example_en_2 = 'She woke up with a bruise on her shin from bumping the table.', example_ko_2 = '그녀는 테이블에 부딪혀 정강이에 멍이 든 채로 일어났어요.', example_en_3 = 'Applying ice can help reduce the size of a bruise.', example_ko_3 = '얼음을 대면 멍의 크기를 줄이는 데 도움이 돼요.', example_en_4 = 'The bruise changed colour from blue to yellow as it healed.', example_ko_4 = '멍은 아물면서 파란색에서 노란색으로 변했어요.', example_en_5 = 'He got a bruise on his knee during the football match.', example_ko_5 = '그는 축구 경기 중에 무릎에 멍이 들었어요.' WHERE id = 'w_body_B1_07';
UPDATE words SET example_en_2 = 'He rested his ankle sprain by staying off his feet.', example_ko_2 = '그는 발목 삠을 치료하기 위해 발을 들고 쉬었어요.', example_en_3 = 'A sprain takes longer to heal than a simple bruise.', example_ko_3 = '염좌는 단순한 멍보다 낫는 데 더 오래 걸려요.', example_en_4 = 'The doctor confirmed it was a mild sprain and not a fracture.', example_ko_4 = '의사는 골절이 아니라 가벼운 염좌라고 확인해줬어요.', example_en_5 = 'She iced the sprain every few hours to reduce swelling.', example_ko_5 = '그녀는 부기를 줄이기 위해 몇 시간마다 얼음찜질을 했어요.' WHERE id = 'w_body_B1_08';
