UPDATE words SET example_en_2 = 'He felt his pulse speed up before the race.', example_ko_2 = '그는 경기 전에 맥박이 빨라지는 것을 느꼈어요.', example_en_3 = 'A resting pulse of sixty beats per minute is considered healthy.', example_ko_3 = '안정시 맥박이 분당 60회이면 건강한 것으로 여겨져요.', example_en_4 = 'The doctor found an irregular pulse during the check-up.', example_ko_4 = '의사는 검진 중 불규칙한 맥박을 발견했어요.', example_en_5 = 'She counted the pulse by pressing her fingers to the wrist.', example_ko_5 = '그녀는 손목에 손가락을 대어 맥박을 세었어요.' WHERE id = 'w_body_B1_10';
UPDATE words SET example_en_2 = 'It takes a few hours to digest a large meal.', example_ko_2 = '많은 양의 식사를 소화하는 데 몇 시간이 걸려요.', example_en_3 = 'She drank herbal tea to help her digest dinner.', example_ko_3 = '그녀는 저녁식사를 소화하는 데 도움이 되도록 허브차를 마셨어요.', example_en_4 = 'Chewing food slowly helps the stomach digest it more easily.', example_ko_4 = '음식을 천천히 씹으면 위가 소화하기 더 쉬워져요.', example_en_5 = 'The information was a lot to digest at once.', example_ko_5 = '그 정보는 한 번에 소화하기에 너무 많은 양이었어요.' WHERE id = 'w_body_B1_11';
UPDATE words SET example_en_2 = 'Cold weather can slow down circulation in the hands.', example_ko_2 = '차가운 날씨는 손의 혈액 순환을 느리게 할 수 있어요.', example_en_3 = 'She massaged her legs to improve circulation after the flight.', example_ko_3 = '그녀는 비행 후 혈액 순환을 개선하기 위해 다리를 마사지했어요.', example_en_4 = 'Good circulation keeps the skin looking healthy.', example_ko_4 = '좋은 혈액 순환은 피부를 건강해 보이게 유지해줘요.', example_en_5 = 'The doctor said his circulation had improved significantly.', example_ko_5 = '의사는 그의 혈액 순환이 크게 개선됐다고 했어요.' WHERE id = 'w_body_B1_12';
