UPDATE words SET example_en_2 = 'Her metabolism slowed down as she got older.', example_ko_2 = '그녀는 나이가 들면서 신진대사가 느려졌어요.', example_en_3 = 'Cold exposure can temporarily boost metabolism.', example_ko_3 = '냉기에 노출되면 일시적으로 신진대사가 촉진될 수 있어요.', example_en_4 = 'He ate small, frequent meals to keep his metabolism active.', example_ko_4 = '그는 신진대사를 활발하게 유지하기 위해 소량씩 자주 먹었어요.', example_en_5 = 'Thyroid problems can significantly affect metabolism.', example_ko_5 = '갑상선 문제는 신진대사에 크게 영향을 미칠 수 있어요.' WHERE id = 'w_body_B2_01';
UPDATE words SET example_en_2 = 'Growth hormones are most active during sleep.', example_ko_2 = '성장 호르몬은 수면 중에 가장 활발해요.', example_en_3 = 'The hormone levels in her blood were tested.', example_ko_3 = '그녀의 혈중 호르몬 수치가 검사됐어요.', example_en_4 = 'Exercise triggers the release of beneficial hormones.', example_ko_4 = '운동은 유익한 호르몬의 분비를 촉진해요.', example_en_5 = 'Puberty involves significant changes in hormone levels.', example_ko_5 = '사춘기에는 호르몬 수치에 큰 변화가 생겨요.' WHERE id = 'w_body_B2_02';
UPDATE words SET example_en_2 = 'The enzyme activity decreased at low temperatures.', example_ko_2 = '낮은 온도에서 효소 활성이 감소했어요.', example_en_3 = 'Some people lack the enzyme needed to digest lactose.', example_ko_3 = '일부 사람들은 유당을 소화하는 데 필요한 효소가 부족해요.', example_en_4 = 'Enzymes in saliva begin breaking down food immediately.', example_ko_4 = '침 속의 효소는 즉시 음식을 분해하기 시작해요.', example_en_5 = 'The lab studied how the enzyme affected cell function.', example_ko_5 = '연구소는 효소가 세포 기능에 어떻게 영향을 미치는지 연구했어요.' WHERE id = 'w_body_B2_03';
UPDATE words SET example_en_2 = 'Different tissues in the body have different functions.', example_ko_2 = '신체의 다양한 조직은 각각 다른 기능을 가지고 있어요.', example_en_3 = 'She blew her nose with a soft tissue.', example_ko_3 = '그녀는 부드러운 티슈로 코를 풀었어요.', example_en_4 = 'The biopsy showed abnormal growth in the tissue.', example_ko_4 = '생검 결과 조직에 비정상적인 성장이 나타났어요.', example_en_5 = 'Connective tissue holds different body parts together.', example_ko_5 = '결합 조직은 신체의 다양한 부위를 함께 붙들어줘요.' WHERE id = 'w_body_B2_04';
UPDATE words SET example_en_2 = 'Each cell carries a copy of the body''s DNA.', example_ko_2 = '각 세포는 신체의 DNA 복사본을 가지고 있어요.', example_en_3 = 'White blood cells attack bacteria and viruses.', example_ko_3 = '백혈구는 박테리아와 바이러스를 공격해요.', example_en_4 = 'Cancer occurs when cells start to divide uncontrollably.', example_ko_4 = '암은 세포가 통제 없이 분열하기 시작할 때 발생해요.', example_en_5 = 'Scientists observed the cell under a powerful microscope.', example_ko_5 = '과학자들은 강력한 현미경으로 세포를 관찰했어요.' WHERE id = 'w_body_B2_05';
UPDATE words SET example_en_2 = 'The brain consumes large amounts of oxygen to function.', example_ko_2 = '뇌는 기능하기 위해 많은 양의 산소를 소비해요.', example_en_3 = 'Altitude sickness occurs when there is less oxygen in the air.', example_ko_3 = '고산병은 공기 중 산소가 적을 때 발생해요.', example_en_4 = 'The paramedic gave the patient oxygen through a mask.', example_ko_4 = '응급 구조대원이 마스크를 통해 환자에게 산소를 공급했어요.', example_en_5 = 'Exercise increases the body''s demand for oxygen.', example_ko_5 = '운동은 몸의 산소 요구량을 증가시켜요.' WHERE id = 'w_body_B2_06';
UPDATE words SET example_en_2 = 'The doctor examined the blood vessels in his eye.', example_ko_2 = '의사는 그의 눈의 혈관을 검사했어요.', example_en_3 = 'Smoking narrows blood vessels and reduces circulation.', example_ko_3 = '흡연은 혈관을 좁히고 혈액 순환을 감소시켜요.', example_en_4 = 'Exercise helps keep blood vessels flexible and healthy.', example_ko_4 = '운동은 혈관을 유연하고 건강하게 유지하는 데 도움이 돼요.', example_en_5 = 'She could see tiny blood vessels on the surface of the skin.', example_ko_5 = '그녀는 피부 표면의 작은 혈관들을 볼 수 있었어요.' WHERE id = 'w_body_B2_07';
UPDATE words SET example_en_2 = 'A skeleton model was used in the anatomy lecture.', example_ko_2 = '해부학 강의에서 골격 모형이 사용됐어요.', example_en_3 = 'Bones in the skeleton protect the internal organs.', example_ko_3 = '골격의 뼈들은 내부 장기를 보호해요.', example_en_4 = 'The skeleton of a child has more bones than an adult.', example_ko_4 = '아이의 골격은 성인보다 더 많은 뼈를 가지고 있어요.', example_en_5 = 'She studied the human skeleton in detail for the exam.', example_ko_5 = '그녀는 시험을 위해 인체 골격을 자세히 공부했어요.' WHERE id = 'w_body_B2_08';
UPDATE words SET example_en_2 = 'He stretched his joints gently before the workout.', example_ko_2 = '그는 운동 전에 관절을 부드럽게 스트레칭했어요.', example_en_3 = 'Cold weather can make the joints feel stiff.', example_ko_3 = '추운 날씨는 관절을 뻣뻣하게 느끼게 할 수 있어요.', example_en_4 = 'The doctor recommended surgery on the damaged joint.', example_ko_4 = '의사는 손상된 관절 수술을 권유했어요.', example_en_5 = 'Omega-3 fatty acids can help reduce joint pain.', example_ko_5 = '오메가-3 지방산은 관절 통증을 줄이는 데 도움이 될 수 있어요.' WHERE id = 'w_body_B2_09';
UPDATE words SET example_en_2 = 'The ligament connected the two bones at the joint.', example_ko_2 = '인대는 관절에서 두 뼈를 연결했어요.', example_en_3 = 'He stretched a ligament in his shoulder while swimming.', example_ko_3 = '그는 수영 중에 어깨 인대가 늘어났어요.', example_en_4 = 'A ligament injury can take months to heal completely.', example_ko_4 = '인대 부상은 완전히 낫는 데 몇 달이 걸릴 수 있어요.', example_en_5 = 'The physiotherapist treated her damaged ligament carefully.', example_ko_5 = '물리치료사가 그녀의 손상된 인대를 조심스럽게 치료했어요.' WHERE id = 'w_body_B2_10';
UPDATE words SET example_en_2 = 'A torn tendon requires surgery and long rest.', example_ko_2 = '힘줄이 파열되면 수술과 긴 휴식이 필요해요.', example_en_3 = 'The tendon attaches the calf muscle to the heel bone.', example_ko_3 = '힘줄은 종아리 근육을 발뒤꿈치 뼈에 연결해요.', example_en_4 = 'She felt a sharp snap in her tendon during the jump.', example_ko_4 = '그녀는 점프 중 힘줄에서 날카로운 끊어지는 느낌을 느꼈어요.', example_en_5 = 'Stretching regularly keeps tendons flexible and strong.', example_ko_5 = '규칙적인 스트레칭은 힘줄을 유연하고 강하게 유지해줘요.' WHERE id = 'w_body_B2_11';
UPDATE words SET example_en_2 = 'Cartilage in the nose gives it its shape.', example_ko_2 = '코의 연골이 코의 모양을 만들어줘요.', example_en_3 = 'He was told his knee cartilage had worn down over time.', example_ko_3 = '그는 무릎 연골이 시간이 지나면서 닳았다는 말을 들었어요.', example_en_4 = 'Unlike bone, cartilage does not have blood vessels.', example_ko_4 = '뼈와 달리 연골에는 혈관이 없어요.', example_en_5 = 'The ear is supported by flexible cartilage.', example_ko_5 = '귀는 유연한 연골에 의해 지지돼요.' WHERE id = 'w_body_B2_12';
UPDATE words SET example_en_2 = 'Varicose veins become swollen and visible under the skin.', example_ko_2 = '정맥류는 피부 아래에서 부어올라 보여요.', example_en_3 = 'The nurse found a suitable vein for the blood test.', example_ko_3 = '간호사는 혈액 검사를 위한 적합한 정맥을 찾았어요.', example_en_4 = 'Dehydration can make veins harder to find.', example_ko_4 = '탈수 상태에서는 정맥을 찾기가 더 어려울 수 있어요.', example_en_5 = 'Veins carry deoxygenated blood back to the heart.', example_ko_5 = '정맥은 산소가 제거된 혈액을 심장으로 돌려보내요.' WHERE id = 'w_body_B2_13';
UPDATE words SET example_en_2 = 'He had a blockage in a major artery in his heart.', example_ko_2 = '그의 심장 주요 동맥에 막힘이 있었어요.', example_en_3 = 'The surgeon repaired the damaged artery with a graft.', example_ko_3 = '외과의사는 이식편으로 손상된 동맥을 수리했어요.', example_en_4 = 'An artery carries oxygen-rich blood from the heart.', example_ko_4 = '동맥은 심장에서 산소가 풍부한 혈액을 운반해요.', example_en_5 = 'High cholesterol can narrow the walls of an artery.', example_ko_5 = '높은 콜레스테롤은 동맥 벽을 좁힐 수 있어요.' WHERE id = 'w_body_B2_14';
UPDATE words SET example_en_2 = 'The doctor felt the lymph nodes in his neck.', example_ko_2 = '의사는 그의 목에 있는 림프절을 촉진했어요.', example_en_3 = 'Swollen lymph nodes often mean the body is fighting an infection.', example_ko_3 = '부어오른 림프절은 종종 몸이 감염과 싸우고 있다는 것을 의미해요.', example_en_4 = 'Lymph nodes are part of the body''s immune defence system.', example_ko_4 = '림프절은 신체 면역 방어 체계의 일부예요.', example_en_5 = 'She had a painless swelling in her lymph node after the illness.', example_ko_5 = '그녀는 병을 앓고 나서 림프절에 통증 없는 부종이 생겼어요.' WHERE id = 'w_body_B2_15';
UPDATE words SET example_en_2 = 'Antibodies remain in the blood long after infection.', example_ko_2 = '항체는 감염 후에도 오랫동안 혈액 속에 남아있어요.', example_en_3 = 'A blood test can check for the presence of certain antibodies.', example_ko_3 = '혈액 검사로 특정 항체의 존재 여부를 확인할 수 있어요.', example_en_4 = 'The body creates new antibodies when exposed to a new pathogen.', example_ko_4 = '새로운 병원체에 노출되면 신체는 새로운 항체를 만들어요.', example_en_5 = 'Maternal antibodies protect newborns in their first months.', example_ko_5 = '모체 항체는 생후 몇 달 동안 신생아를 보호해줘요.' WHERE id = 'w_body_B2_16';
UPDATE words SET example_en_2 = 'The inflammation in his knee made walking painful.', example_ko_2 = '무릎의 염증으로 인해 걷기가 고통스러웠어요.', example_en_3 = 'Anti-inflammatory medication helped reduce the swelling.', example_ko_3 = '소염제가 부기를 줄이는 데 도움이 됐어요.', example_en_4 = 'Chronic inflammation is linked to various serious diseases.', example_ko_4 = '만성 염증은 여러 심각한 질병과 관련이 있어요.', example_en_5 = 'She applied ice to manage the inflammation after the fall.', example_ko_5 = '그녀는 넘어진 후 염증을 관리하기 위해 얼음을 댔어요.' WHERE id = 'w_body_B2_17';
UPDATE words SET example_en_2 = 'He was diagnosed with a chronic condition that required ongoing care.', example_ko_2 = '그는 지속적인 치료가 필요한 만성 질환을 진단받았어요.', example_en_3 = 'Chronic stress can lead to serious health problems over time.', example_ko_3 = '만성 스트레스는 시간이 지나면서 심각한 건강 문제를 유발할 수 있어요.', example_en_4 = 'A chronic cough lasting more than three weeks should be examined.', example_ko_4 = '3주 이상 지속되는 만성 기침은 진찰을 받아야 해요.', example_en_5 = 'Many people live full lives despite chronic illness.', example_ko_5 = '많은 사람들이 만성 질환에도 불구하고 충실하게 살아가요.' WHERE id = 'w_body_B2_18';
UPDATE words SET example_en_2 = 'The acute pain in her chest required immediate attention.', example_ko_2 = '그녀의 가슴에 느껴지는 급성 통증은 즉각적인 처치가 필요했어요.', example_en_3 = 'He experienced an acute attack of asthma during the run.', example_ko_3 = '그는 달리는 중에 급성 천식 발작을 경험했어요.', example_en_4 = 'An acute sense of smell helped her detect the problem.', example_ko_4 = '예민한 후각이 그녀가 문제를 감지하는 데 도움이 됐어요.', example_en_5 = 'Acute illness usually develops quickly and lasts a short time.', example_ko_5 = '급성 질환은 보통 빠르게 발생하고 짧은 시간 동안 지속돼요.' WHERE id = 'w_body_B2_19';
UPDATE words SET example_en_2 = 'He described his symptoms to the doctor clearly.', example_ko_2 = '그는 의사에게 증상을 명확하게 설명했어요.', example_en_3 = 'Fever is one of the first symptoms of the flu.', example_ko_3 = '발열은 독감의 첫 번째 증상 중 하나예요.', example_en_4 = 'She monitored her symptoms closely for a week.', example_ko_4 = '그녀는 일주일 동안 증상을 면밀히 관찰했어요.', example_en_5 = 'Some conditions cause no symptoms in the early stages.', example_ko_5 = '일부 질환은 초기에 증상이 없어요.' WHERE id = 'w_body_B2_20';
UPDATE words SET example_en_2 = 'The diagnosis was confirmed after several tests.', example_ko_2 = '여러 검사 후에 진단이 확인됐어요.', example_en_3 = 'She was relieved to receive a clear diagnosis at last.', example_ko_3 = '그녀는 마침내 명확한 진단을 받아 안도했어요.', example_en_4 = 'Getting a second opinion can help confirm a difficult diagnosis.', example_ko_4 = '두 번째 의견을 구하면 어려운 진단을 확인하는 데 도움이 돼요.', example_en_5 = 'Modern technology has made the diagnosis of disease faster.', example_ko_5 = '현대 기술은 질병 진단을 더 빠르게 만들었어요.' WHERE id = 'w_body_B2_21';
UPDATE words SET example_en_2 = 'She found anatomy fascinating and decided to study medicine.', example_ko_2 = '그녀는 해부학이 흥미롭다고 느껴 의학을 공부하기로 했어요.', example_en_3 = 'The anatomy of the hand is surprisingly complex.', example_ko_3 = '손의 해부 구조는 놀라울 정도로 복잡해요.', example_en_4 = 'He used a detailed anatomy diagram for his presentation.', example_ko_4 = '그는 발표를 위해 상세한 해부학 도표를 사용했어요.', example_en_5 = 'Understanding anatomy is essential for medical professionals.', example_ko_5 = '해부학을 이해하는 것은 의료 전문가에게 필수적이에요.' WHERE id = 'w_body_B2_22';
UPDATE words SET example_en_2 = 'She studied physiology to understand how the heart works.', example_ko_2 = '그녀는 심장이 어떻게 작동하는지 이해하기 위해 생리학을 공부했어요.', example_en_3 = 'Human physiology changes significantly during pregnancy.', example_ko_3 = '임신 중에는 인체 생리학이 크게 변화해요.', example_en_4 = 'Exercise physiology explores how the body responds to training.', example_ko_4 = '운동 생리학은 신체가 훈련에 어떻게 반응하는지 탐구해요.', example_en_5 = 'The lecture covered the physiology of the respiratory system.', example_ko_5 = '그 강의는 호흡기 계통의 생리학을 다뤘어요.' WHERE id = 'w_body_B2_23';
UPDATE words SET example_en_2 = 'A single neuron can connect to thousands of other neurons.', example_ko_2 = '하나의 뉴런은 수천 개의 다른 뉴런과 연결될 수 있어요.', example_en_3 = 'The neuron fired rapidly when stimulated.', example_ko_3 = '뉴런은 자극을 받으면 빠르게 발화해요.', example_en_4 = 'New neurons can form in certain parts of the adult brain.', example_ko_4 = '성인 뇌의 특정 부위에서 새로운 뉴런이 생겨날 수 있어요.', example_en_5 = 'Damage to neurons in the spinal cord can cause paralysis.', example_ko_5 = '척수 뉴런이 손상되면 마비가 올 수 있어요.' WHERE id = 'w_body_B2_24';
UPDATE words SET example_en_2 = 'The frontal cortex develops last during adolescence.', example_ko_2 = '전두엽 피질은 청소년기에 가장 마지막으로 발달해요.', example_en_3 = 'The cortex is responsible for language and reasoning.', example_ko_3 = '피질은 언어와 추론을 담당해요.', example_en_4 = 'Scientists mapped the activity of the cortex during sleep.', example_ko_4 = '과학자들은 수면 중 피질의 활동을 지도화했어요.', example_en_5 = 'Damage to the visual cortex can affect how we see.', example_ko_5 = '시각 피질이 손상되면 시각에 영향을 줄 수 있어요.' WHERE id = 'w_body_B2_25';
UPDATE words SET example_en_2 = 'The adrenal gland produces hormones in response to stress.', example_ko_2 = '부신은 스트레스에 반응하여 호르몬을 분비해요.', example_en_3 = 'He had a small cyst on his salivary gland.', example_ko_3 = '그는 침샘에 작은 낭종이 있었어요.', example_en_4 = 'The pituitary gland is often called the master gland.', example_ko_4 = '뇌하수체는 종종 마스터 분비선이라고 불려요.', example_en_5 = 'A malfunctioning gland can cause hormonal imbalances.', example_ko_5 = '분비선이 제대로 작동하지 않으면 호르몬 불균형이 생길 수 있어요.' WHERE id = 'w_body_B2_26';
UPDATE words SET example_en_2 = 'The liver is the largest internal organ in the body.', example_ko_2 = '간은 신체에서 가장 큰 내부 장기예요.', example_en_3 = 'He donated one of his organs to save a stranger''s life.', example_ko_3 = '그는 낯선 사람의 생명을 구하기 위해 장기 하나를 기증했어요.', example_en_4 = 'Each organ in the body has a specific and vital role.', example_ko_4 = '신체의 각 장기는 특정하고 중요한 역할을 가지고 있어요.', example_en_5 = 'Organ transplant surgery has saved millions of lives.', example_ko_5 = '장기 이식 수술은 수백만 명의 생명을 구했어요.' WHERE id = 'w_body_B2_27';
UPDATE words SET example_en_2 = 'Each organ has a specific function in the digestive system.', example_ko_2 = '각 장기는 소화 계통에서 특정 기능을 가지고 있어요.', example_en_3 = 'The function of the spleen is to filter the blood.', example_ko_3 = '비장의 기능은 혈액을 거르는 것이에요.', example_en_4 = 'The test checked the function of her thyroid.', example_ko_4 = '검사는 그녀의 갑상선 기능을 확인했어요.', example_en_5 = 'She explained the function of white blood cells.', example_ko_5 = '그녀는 백혈구의 기능을 설명했어요.' WHERE id = 'w_body_B2_28';
UPDATE words SET example_en_2 = 'Scientists examined the structure of the protein closely.', example_ko_2 = '과학자들은 단백질의 구조를 면밀히 조사했어요.', example_en_3 = 'The internal structure of the eye is surprisingly intricate.', example_ko_3 = '눈의 내부 구조는 놀라울 정도로 복잡해요.', example_en_4 = 'The class learned about the structure of the cell membrane.', example_ko_4 = '수업에서 세포막의 구조를 배웠어요.', example_en_5 = 'A strong internal structure is essential for healthy bones.', example_ko_5 = '건강한 뼈를 위해서는 강한 내부 구조가 필수적이에요.' WHERE id = 'w_body_B2_29';
UPDATE words SET example_en_2 = 'The doctor noticed abnormal cell growth in the sample.', example_ko_2 = '의사는 샘플에서 비정상적인 세포 성장을 발견했어요.', example_en_3 = 'The test came back showing abnormal results.', example_ko_3 = '검사 결과 비정상적인 수치가 나왔어요.', example_en_4 = 'Abnormal breathing patterns can indicate a medical problem.', example_ko_4 = '비정상적인 호흡 패턴은 의학적 문제를 나타낼 수 있어요.', example_en_5 = 'The X-ray showed an abnormal shadow near the lung.', example_ko_5 = 'X레이에서 폐 근처에 비정상적인 그림자가 나타났어요.' WHERE id = 'w_body_B2_30';
UPDATE words SET example_en_2 = 'Her muscles began to degenerate without regular use.', example_ko_2 = '규칙적으로 사용하지 않자 그녀의 근육이 퇴화하기 시작했어요.', example_en_3 = 'The disease can cause nerve cells to degenerate.', example_ko_3 = '그 질병은 신경 세포를 퇴화시킬 수 있어요.', example_en_4 = 'His vision began to degenerate in his sixties.', example_ko_4 = '그의 시력은 60대에 퇴화하기 시작했어요.', example_en_5 = 'The spinal discs can degenerate over years of heavy lifting.', example_ko_5 = '척추 디스크는 수년간의 무거운 물건 들기로 퇴화할 수 있어요.' WHERE id = 'w_body_B2_31';
UPDATE words SET example_en_2 = 'Stem cells can regenerate damaged tissue in the body.', example_ko_2 = '줄기세포는 신체의 손상된 조직을 재생할 수 있어요.', example_en_3 = 'Liver cells can regenerate after minor damage.', example_ko_3 = '간세포는 경미한 손상 후 재생될 수 있어요.', example_en_4 = 'The treatment aimed to help the nerves regenerate.', example_ko_4 = '그 치료는 신경이 재생되도록 돕는 것을 목표로 했어요.', example_en_5 = 'Researchers are studying how to help cartilage regenerate.', example_ko_5 = '연구자들은 연골이 재생되는 방법을 연구하고 있어요.' WHERE id = 'w_body_B2_32';
UPDATE words SET example_en_2 = 'Hormones help regulate blood sugar after meals.', example_ko_2 = '호르몬은 식사 후 혈당을 조절하는 데 도움이 돼요.', example_en_3 = 'The skin regulates body temperature through sweating.', example_ko_3 = '피부는 발한을 통해 체온을 조절해요.', example_en_4 = 'She exercised to help regulate her sleep patterns.', example_ko_4 = '그녀는 수면 패턴을 조절하는 데 도움이 되도록 운동했어요.', example_en_5 = 'The kidneys regulate the balance of fluids in the body.', example_ko_5 = '신장은 체내 수분 균형을 조절해요.' WHERE id = 'w_body_B2_33';
UPDATE words SET example_en_2 = 'Caffeine stimulates the central nervous system.', example_ko_2 = '카페인은 중추 신경계를 자극해요.', example_en_3 = 'Sunlight stimulates the production of vitamin D.', example_ko_3 = '햇빛은 비타민 D 생성을 자극해요.', example_en_4 = 'The doctor used electrical impulses to stimulate the muscle.', example_ko_4 = '의사는 전기 자극으로 근육을 자극했어요.', example_en_5 = 'Reading before bed can stimulate the mind too much.', example_ko_5 = '자기 전에 독서를 하면 뇌를 너무 자극할 수 있어요.' WHERE id = 'w_body_B2_34';
UPDATE words SET example_en_2 = 'The drug helps inhibit the spread of the virus.', example_ko_2 = '그 약은 바이러스 확산을 억제하는 데 도움이 돼요.', example_en_3 = 'A high dose of medication may inhibit nerve function.', example_ko_3 = '높은 용량의 약은 신경 기능을 억제할 수 있어요.', example_en_4 = 'The body produces chemicals that naturally inhibit pain.', example_ko_4 = '신체는 통증을 자연스럽게 억제하는 화학 물질을 생성해요.', example_en_5 = 'Stress can inhibit the digestive system from working properly.', example_ko_5 = '스트레스는 소화 계통이 제대로 작동하는 것을 억제할 수 있어요.' WHERE id = 'w_body_B2_35';

