UPDATE words SET example_en_2 = 'The autonomic nervous system manages digestion automatically.', example_ko_2 = '자율 신경계는 자동으로 소화를 관리해요.', example_en_3 = 'Fight or flight responses are driven by the autonomic nervous system.', example_ko_3 = '싸움 또는 도주 반응은 자율 신경계에 의해 조절돼요.', example_en_4 = 'The autonomic nervous system operates without conscious control.', example_ko_4 = '자율 신경계는 의식적 통제 없이 작동해요.', example_en_5 = 'Yoga can help calm the autonomic nervous system.', example_ko_5 = '요가는 자율 신경계를 진정시키는 데 도움이 될 수 있어요.' WHERE id = 'w_body_C1_01';
UPDATE words SET example_en_2 = 'She experienced somatic symptoms of anxiety including muscle tension.', example_ko_2 = '그녀는 근육 긴장을 포함한 불안의 신체적 증상을 경험했어요.', example_en_3 = 'Somatic awareness means tuning into how your body feels.', example_ko_3 = '신체 인식은 몸이 어떻게 느끼는지에 집중하는 것을 의미해요.', example_en_4 = 'Somatic cells make up the majority of the human body.', example_ko_4 = '체세포는 인체의 대부분을 구성해요.', example_en_5 = 'The therapist used a somatic approach to treat trauma.', example_ko_5 = '치료사는 트라우마를 치료하기 위해 신체적 접근법을 사용했어요.' WHERE id = 'w_body_C1_02';
UPDATE words SET example_en_2 = 'Peripheral neuropathy causes tingling in the hands and feet.', example_ko_2 = '말초 신경병증은 손과 발에 저릿한 느낌을 유발해요.', example_en_3 = 'Blood flow to peripheral areas can be affected by cold.', example_ko_3 = '말초 부위로의 혈류는 추위에 의해 영향을 받을 수 있어요.', example_en_4 = 'The peripheral vision allows us to detect movement from the side.', example_ko_4 = '말초 시야는 측면의 움직임을 감지할 수 있게 해줘요.', example_en_5 = 'Peripheral arteries carry blood to the limbs.', example_ko_5 = '말초 동맥은 사지에 혈액을 공급해요.' WHERE id = 'w_body_C1_03';
UPDATE words SET example_en_2 = 'Cardiovascular fitness improves with regular aerobic exercise.', example_ko_2 = '규칙적인 유산소 운동으로 심혈관 체력이 향상돼요.', example_en_3 = 'The patient had a history of cardiovascular disease.', example_ko_3 = '그 환자는 심혈관 질환 병력이 있었어요.', example_en_4 = 'A healthy diet reduces the risk of cardiovascular problems.', example_ko_4 = '건강한 식단은 심혈관 문제의 위험을 줄여줘요.', example_en_5 = 'Swimming is one of the best cardiovascular workouts.', example_ko_5 = '수영은 최고의 심혈관 운동 중 하나예요.' WHERE id = 'w_body_C1_04';
UPDATE words SET example_en_2 = 'Respiratory conditions like asthma can be managed with inhalers.', example_ko_2 = '천식과 같은 호흡기 질환은 흡입기로 관리할 수 있어요.', example_en_3 = 'The cold affected her respiratory system badly.', example_ko_3 = '감기가 그녀의 호흡기 계통에 심각한 영향을 미쳤어요.', example_en_4 = 'Good air quality supports respiratory health.', example_ko_4 = '좋은 공기 질은 호흡기 건강을 지원해요.', example_en_5 = 'The nurse monitored his respiratory rate closely.', example_ko_5 = '간호사는 그의 호흡수를 면밀히 관찰했어요.' WHERE id = 'w_body_C1_05';
UPDATE words SET example_en_2 = 'An endocrine disorder can affect many body systems at once.', example_ko_2 = '내분비 장애는 한 번에 많은 신체 계통에 영향을 줄 수 있어요.', example_en_3 = 'She was referred to an endocrine specialist for her thyroid.', example_ko_3 = '그녀는 갑상선 때문에 내분비 전문의에게 의뢰됐어요.', example_en_4 = 'The endocrine glands release hormones directly into the blood.', example_ko_4 = '내분비선은 혈액으로 호르몬을 직접 분비해요.', example_en_5 = 'Stress can disrupt the endocrine system''s balance.', example_ko_5 = '스트레스는 내분비계의 균형을 방해할 수 있어요.' WHERE id = 'w_body_C1_06';
