UPDATE words SET example_en_2 = 'Epigenetics shows that lifestyle choices can affect gene expression.', example_ko_2 = '후성유전학은 생활 방식 선택이 유전자 발현에 영향을 줄 수 있음을 보여줘요.', example_en_3 = 'Research in epigenetics has changed how we think about inheritance.', example_ko_3 = '후성유전학 연구는 우리가 유전에 대해 생각하는 방식을 바꿨어요.', example_en_4 = 'Stress may leave epigenetic marks that affect future generations.', example_ko_4 = '스트레스는 미래 세대에 영향을 미치는 후성유전학적 흔적을 남길 수 있어요.', example_en_5 = 'She specialised in epigenetics during her doctoral research.', example_ko_5 = '그녀는 박사 연구 중에 후성유전학을 전공했어요.' WHERE id = 'w_body_C2_01';
UPDATE words SET example_en_2 = 'Neuroplasticity means the brain can recover from certain injuries.', example_ko_2 = '신경 가소성은 뇌가 특정 부상에서 회복할 수 있음을 의미해요.', example_en_3 = 'She used neuroplasticity exercises to improve her memory.', example_ko_3 = '그녀는 기억력을 향상시키기 위해 신경 가소성 운동을 활용했어요.', example_en_4 = 'Neuroplasticity is greatest in early childhood.', example_ko_4 = '신경 가소성은 유아기에 가장 활발해요.', example_en_5 = 'The discovery of neuroplasticity changed neuroscience profoundly.', example_ko_5 = '신경 가소성의 발견은 신경과학을 근본적으로 바꿨어요.' WHERE id = 'w_body_C2_02';
UPDATE words SET example_en_2 = 'A phenotype results from a combination of genes and environment.', example_ko_2 = '표현형은 유전자와 환경의 조합에서 비롯돼요.', example_en_3 = 'The same genotype can produce a different phenotype.', example_ko_3 = '같은 유전자형이라도 다른 표현형을 만들어낼 수 있어요.', example_en_4 = 'Scientists studied how temperature affected the plant phenotype.', example_ko_4 = '과학자들은 온도가 식물 표현형에 어떤 영향을 미치는지 연구했어요.', example_en_5 = 'Height is a complex phenotype influenced by many genes.', example_ko_5 = '키는 많은 유전자의 영향을 받는 복잡한 표현형이에요.' WHERE id = 'w_body_C2_03';
UPDATE words SET example_en_2 = 'Identical twins share the same genotype but may differ in phenotype.', example_ko_2 = '일란성 쌍둥이는 같은 유전자형을 공유하지만 표현형은 다를 수 있어요.', example_en_3 = 'Scientists compared the genotype of diseased and healthy cells.', example_ko_3 = '과학자들은 병든 세포와 건강한 세포의 유전자형을 비교했어요.', example_en_4 = 'The genotype of an organism cannot be observed directly.', example_ko_4 = '유기체의 유전자형은 직접 관찰할 수 없어요.', example_en_5 = 'Her genotype indicated a risk for a hereditary condition.', example_ko_5 = '그녀의 유전자형은 유전성 질환의 위험을 나타냈어요.' WHERE id = 'w_body_C2_04';
UPDATE words SET example_en_2 = 'Ontogenesis begins at the moment of fertilisation.', example_ko_2 = '개체 발생은 수정 순간부터 시작돼요.', example_en_3 = 'He wrote his thesis on the ontogenesis of the human nervous system.', example_ko_3 = '그는 인간 신경계의 개체 발생에 관한 논문을 작성했어요.', example_en_4 = 'The stages of ontogenesis are studied in developmental biology.', example_ko_4 = '개체 발생의 단계는 발생생물학에서 연구돼요.', example_en_5 = 'Each step of ontogenesis is carefully controlled by genes.', example_ko_5 = '개체 발생의 각 단계는 유전자에 의해 세밀하게 통제돼요.' WHERE id = 'w_body_C2_05';
UPDATE words SET example_en_2 = 'Immunomodulation is used in the treatment of autoimmune diseases.', example_ko_2 = '면역 조절은 자가면역 질환 치료에 사용돼요.', example_en_3 = 'The drug achieved immunomodulation without serious side effects.', example_ko_3 = '그 약물은 심각한 부작용 없이 면역 조절을 달성했어요.', example_en_4 = 'Research into immunomodulation may lead to better cancer therapies.', example_ko_4 = '면역 조절 연구는 더 나은 암 치료법으로 이어질 수 있어요.', example_en_5 = 'Probiotics support immunomodulation in the gut.', example_ko_5 = '프로바이오틱스는 장에서의 면역 조절을 지원해요.' WHERE id = 'w_body_C2_06';
UPDATE words SET example_en_2 = 'Disruption of synaptic plasticity underlies many brain disorders.', example_ko_2 = '시냅스 가소성의 교란은 많은 뇌 장애의 근원이에요.', example_en_3 = 'Sleep promotes synaptic plasticity and memory consolidation.', example_ko_3 = '수면은 시냅스 가소성과 기억 강화를 촉진해요.', example_en_4 = 'Synaptic plasticity allows the brain to adapt to new information.', example_ko_4 = '시냅스 가소성은 뇌가 새로운 정보에 적응할 수 있게 해줘요.', example_en_5 = 'The experiment measured changes in synaptic plasticity over time.', example_ko_5 = '그 실험은 시간에 따른 시냅스 가소성의 변화를 측정했어요.' WHERE id = 'w_body_C2_07';
UPDATE words SET example_en_2 = 'Aerobic exercise promotes neurogenesis in ageing adults.', example_ko_2 = '유산소 운동은 노인의 신경 발생을 촉진해요.', example_en_3 = 'Neurogenesis in the olfactory bulb continues throughout life.', example_ko_3 = '후구에서의 신경 발생은 평생 동안 계속돼요.', example_en_4 = 'Researchers are exploring ways to stimulate neurogenesis after injury.', example_ko_4 = '연구자들은 부상 후 신경 발생을 자극하는 방법을 탐구하고 있어요.', example_en_5 = 'She published a paper on adult neurogenesis in rodents.', example_ko_5 = '그녀는 설치류의 성체 신경 발생에 관한 논문을 발표했어요.' WHERE id = 'w_body_C2_08';
UPDATE words SET example_en_2 = 'Cancer cells evade apoptosis and multiply uncontrollably.', example_ko_2 = '암세포는 세포 자연사를 회피하여 통제 없이 증식해요.', example_en_3 = 'Apoptosis is a key process in embryonic development.', example_ko_3 = '세포 자연사는 배아 발달의 핵심 과정이에요.', example_en_4 = 'Understanding apoptosis may help develop new cancer treatments.', example_ko_4 = '세포 자연사를 이해하면 새로운 암 치료법 개발에 도움이 될 수 있어요.', example_en_5 = 'Cells damaged beyond repair undergo apoptosis naturally.', example_ko_5 = '복구할 수 없을 정도로 손상된 세포는 자연스럽게 세포 자연사를 겪어요.' WHERE id = 'w_body_C2_09';
UPDATE words SET example_en_2 = 'Homeostatic regulation prevents dangerous changes in body chemistry.', example_ko_2 = '항상성 조절은 체내 화학의 위험한 변화를 방지해요.', example_en_3 = 'She studied homeostatic regulation as part of her physiology degree.', example_ko_3 = '그녀는 생리학 학위 과정의 일환으로 항상성 조절을 공부했어요.', example_en_4 = 'Fever is part of homeostatic regulation against infection.', example_ko_4 = '발열은 감염에 대한 항상성 조절의 일부예요.', example_en_5 = 'The kidneys play a central role in homeostatic regulation.', example_ko_5 = '신장은 항상성 조절에서 중심적인 역할을 해요.' WHERE id = 'w_body_C2_10';
UPDATE words SET example_en_2 = 'Myelination improves the efficiency of the nervous system.', example_ko_2 = '수초화는 신경계의 효율성을 향상시켜요.', example_en_3 = 'Incomplete myelination in infants causes slower reflexes.', example_ko_3 = '영아의 불완전한 수초화는 반사를 느리게 해요.', example_en_4 = 'Multiple sclerosis involves the breakdown of myelination.', example_ko_4 = '다발성 경화증은 수초화의 파괴를 수반해요.', example_en_5 = 'Myelination continues into early adulthood in humans.', example_ko_5 = '인간의 수초화는 성인 초기까지 계속돼요.' WHERE id = 'w_body_C2_11';
UPDATE words SET example_en_2 = 'Neurodegeneration in Parkinson''s disease affects movement control.', example_ko_2 = '파킨슨병의 신경 퇴행은 운동 조절에 영향을 미쳐요.', example_en_3 = 'Research aims to slow the process of neurodegeneration.', example_ko_3 = '연구는 신경 퇴행 과정을 늦추는 것을 목표로 해요.', example_en_4 = 'Early diagnosis can sometimes delay neurodegeneration.', example_ko_4 = '조기 진단은 때로는 신경 퇴행을 지연시킬 수 있어요.', example_en_5 = 'She dedicated her career to studying neurodegeneration.', example_ko_5 = '그녀는 신경 퇴행 연구에 자신의 경력을 바쳤어요.' WHERE id = 'w_body_C2_12';
UPDATE words SET example_en_2 = 'A somatic mutation in a lung cell can cause cancer.', example_ko_2 = '폐세포의 체세포 돌연변이는 암을 유발할 수 있어요.', example_en_3 = 'Somatic mutations accumulate over a lifetime of exposure to toxins.', example_ko_3 = '체세포 돌연변이는 평생 독소에 노출되면서 축적돼요.', example_en_4 = 'Not all somatic mutations lead to disease.', example_ko_4 = '모든 체세포 돌연변이가 질병으로 이어지는 것은 아니에요.', example_en_5 = 'Researchers identified the somatic mutation responsible for the tumour.', example_ko_5 = '연구자들은 종양을 유발한 체세포 돌연변이를 확인했어요.' WHERE id = 'w_body_C2_13';
UPDATE words SET example_en_2 = 'Mitosis is triggered by growth factors in the body.', example_ko_2 = '유사분열은 체내 성장인자에 의해 유발돼요.', example_en_3 = 'The stages of mitosis are studied under a microscope.', example_ko_3 = '유사분열의 단계는 현미경으로 연구돼요.', example_en_4 = 'Errors during mitosis can result in chromosomal abnormalities.', example_ko_4 = '유사분열 중 오류는 염색체 이상을 초래할 수 있어요.', example_en_5 = 'Mitosis happens continuously in tissues like skin and bone marrow.', example_ko_5 = '유사분열은 피부나 골수 같은 조직에서 지속적으로 일어나요.' WHERE id = 'w_body_C2_14';
UPDATE words SET example_en_2 = 'Errors in meiosis can result in conditions like Down syndrome.', example_ko_2 = '감수분열의 오류는 다운증후군 같은 질환을 초래할 수 있어요.', example_en_3 = 'Meiosis ensures genetic diversity in offspring.', example_ko_3 = '감수분열은 자손의 유전적 다양성을 보장해요.', example_en_4 = 'She explained the stages of meiosis to her biology class.', example_ko_4 = '그녀는 생물 수업에서 감수분열의 단계를 설명했어요.', example_en_5 = 'Without meiosis, sexual reproduction would not be possible.', example_ko_5 = '감수분열이 없다면 유성 생식은 불가능할 거예요.' WHERE id = 'w_body_C2_15';
UPDATE words SET example_en_2 = 'Decoding the genome opened new possibilities in medicine.', example_ko_2 = '게놈 해독은 의학에서 새로운 가능성을 열었어요.', example_en_3 = 'She read about advances in genome sequencing with great interest.', example_ko_3 = '그녀는 게놈 시퀀싱의 발전에 대해 큰 관심을 가지고 읽었어요.', example_en_4 = 'A person''s genome contains about three billion base pairs.', example_ko_4 = '사람의 게놈은 약 30억 개의 염기쌍을 포함해요.', example_en_5 = 'Genome editing tools are being developed for disease treatment.', example_ko_5 = '게놈 편집 도구가 질병 치료를 위해 개발되고 있어요.' WHERE id = 'w_body_C2_16';
UPDATE words SET example_en_2 = 'Chromosomal analysis can identify inherited conditions.', example_ko_2 = '염색체 분석은 유전 질환을 확인할 수 있어요.', example_en_3 = 'Some chromosomal deletions lead to developmental delays.', example_ko_3 = '일부 염색체 결실은 발달 지연으로 이어져요.', example_en_4 = 'The test revealed a chromosomal duplication.', example_ko_4 = '검사에서 염색체 중복이 발견됐어요.', example_en_5 = 'Chromosomal variation between individuals is normal and common.', example_ko_5 = '개인 간 염색체 변이는 정상적이고 흔한 일이에요.' WHERE id = 'w_body_C2_17';
UPDATE words SET example_en_2 = 'DNA methylation patterns differ between healthy and cancerous cells.', example_ko_2 = '건강한 세포와 암세포 사이에는 DNA 메틸화 패턴이 다르게 나타나요.', example_en_3 = 'Environmental toxins can alter DNA methylation over time.', example_ko_3 = '환경 독소는 시간이 지나면서 DNA 메틸화를 변화시킬 수 있어요.', example_en_4 = 'She studied DNA methylation as part of her epigenetics research.', example_ko_4 = '그녀는 후성유전학 연구의 일환으로 DNA 메틸화를 연구했어요.', example_en_5 = 'DNA methylation is one mechanism through which genes are silenced.', example_ko_5 = 'DNA 메틸화는 유전자가 침묵되는 메커니즘 중 하나예요.' WHERE id = 'w_body_C2_18';
UPDATE words SET example_en_2 = 'Shorter telomeres are linked to a higher risk of disease.', example_ko_2 = '짧은 텔로미어는 질병 위험 증가와 관련이 있어요.', example_en_3 = 'Stress may accelerate the shortening of telomeres.', example_ko_3 = '스트레스는 텔로미어의 단축을 가속화할 수 있어요.', example_en_4 = 'Scientists are exploring how to protect telomere length.', example_ko_4 = '과학자들은 텔로미어 길이를 보호하는 방법을 연구하고 있어요.', example_en_5 = 'Telomere length is used as a marker for biological ageing.', example_ko_5 = '텔로미어 길이는 생물학적 노화의 지표로 사용돼요.' WHERE id = 'w_body_C2_19';
UPDATE words SET example_en_2 = 'Stem cells can be found in bone marrow and blood.', example_ko_2 = '줄기세포는 골수와 혈액에서 발견될 수 있어요.', example_en_3 = 'Stem cell research holds promise for treating spinal injuries.', example_ko_3 = '줄기세포 연구는 척추 부상 치료에 가능성을 가지고 있어요.', example_en_4 = 'Embryonic stem cells are more versatile than adult stem cells.', example_ko_4 = '배아 줄기세포는 성체 줄기세포보다 더 다용도적이에요.', example_en_5 = 'Doctors used stem cells to help rebuild damaged heart tissue.', example_ko_5 = '의사들은 손상된 심장 조직을 재건하기 위해 줄기세포를 사용했어요.' WHERE id = 'w_body_C2_20';
UPDATE words SET example_en_2 = 'An overproduction of cytokines can cause dangerous inflammation.', example_ko_2 = '사이토카인의 과잉 생성은 위험한 염증을 유발할 수 있어요.', example_en_3 = 'Cytokines signal between immune cells during infection.', example_ko_3 = '사이토카인은 감염 중에 면역 세포 사이에서 신호를 전달해요.', example_en_4 = 'Researchers measured cytokine levels in the patient''s blood.', example_ko_4 = '연구자들은 환자의 혈액에서 사이토카인 수치를 측정했어요.', example_en_5 = 'Some therapies target cytokines to reduce autoimmune responses.', example_ko_5 = '일부 치료법은 자가면역 반응을 줄이기 위해 사이토카인을 표적으로 해요.' WHERE id = 'w_body_C2_21';
UPDATE words SET example_en_2 = 'Low levels of neurotransmitters are linked to depression.', example_ko_2 = '낮은 신경전달물질 수치는 우울증과 관련이 있어요.', example_en_3 = 'Neurotransmitters are released at the synapse between neurons.', example_ko_3 = '신경전달물질은 뉴런 사이의 시냅스에서 분비돼요.', example_en_4 = 'The medication increased the availability of the neurotransmitter.', example_ko_4 = '그 약물은 신경전달물질의 가용성을 높였어요.', example_en_5 = 'She studied how exercise affects neurotransmitter levels.', example_ko_5 = '그녀는 운동이 신경전달물질 수치에 어떤 영향을 미치는지 연구했어요.' WHERE id = 'w_body_C2_22';
UPDATE words SET example_en_2 = 'Low serotonin levels are associated with anxiety disorders.', example_ko_2 = '낮은 세로토닌 수치는 불안 장애와 관련이 있어요.', example_en_3 = 'Serotonin also plays a role in regulating appetite.', example_ko_3 = '세로토닌은 식욕 조절에도 역할을 해요.', example_en_4 = 'The drug worked by blocking the reabsorption of serotonin.', example_ko_4 = '그 약물은 세로토닌의 재흡수를 차단하여 작용했어요.', example_en_5 = 'Sunlight helps trigger the production of serotonin in the brain.', example_ko_5 = '햇빛은 뇌에서 세로토닌 생성을 유발하는 데 도움이 돼요.' WHERE id = 'w_body_C2_23';
UPDATE words SET example_en_2 = 'Too much dopamine in certain areas of the brain may cause psychosis.', example_ko_2 = '뇌의 특정 부위에 도파민이 너무 많으면 정신증을 유발할 수 있어요.', example_en_3 = 'She felt a rush of dopamine when she finished the project.', example_ko_3 = '그녀는 프로젝트를 완료했을 때 도파민이 솟구치는 것을 느꼈어요.', example_en_4 = 'Social media can trigger small releases of dopamine with each notification.', example_ko_4 = '소셜 미디어는 알림이 올 때마다 소량의 도파민 분비를 유발할 수 있어요.', example_en_5 = 'Dopamine levels are often lower in people with depression.', example_ko_5 = '우울증이 있는 사람들은 도파민 수치가 종종 낮아요.' WHERE id = 'w_body_C2_24';
UPDATE words SET example_en_2 = 'Cortisol levels naturally rise in the morning to help wake you up.', example_ko_2 = '코르티솔 수치는 아침에 자연적으로 상승하여 잠을 깨는 데 도움이 돼요.', example_en_3 = 'She practised relaxation to keep cortisol levels low.', example_ko_3 = '그녀는 코르티솔 수치를 낮게 유지하기 위해 이완법을 실천했어요.', example_en_4 = 'Chronic stress causes cortisol to remain elevated for long periods.', example_ko_4 = '만성 스트레스는 코르티솔을 장기간 높게 유지시켜요.', example_en_5 = 'The researcher studied how diet affects cortisol secretion.', example_ko_5 = '연구자는 식이 요법이 코르티솔 분비에 어떻게 영향을 미치는지 연구했어요.' WHERE id = 'w_body_C2_25';
UPDATE words SET example_en_2 = 'Oxytocin promotes trust and cooperation between people.', example_ko_2 = '옥시토신은 사람들 사이의 신뢰와 협력을 촉진해요.', example_en_3 = 'Breastfeeding releases large amounts of oxytocin in mothers.', example_ko_3 = '모유 수유는 어머니에게 많은 양의 옥시토신을 분비시켜요.', example_en_4 = 'Listening to music can trigger the release of oxytocin.', example_ko_4 = '음악을 들으면 옥시토신 분비를 유발할 수 있어요.', example_en_5 = 'She studied the role of oxytocin in social bonding behaviour.', example_ko_5 = '그녀는 사회적 유대 행동에서 옥시토신의 역할을 연구했어요.' WHERE id = 'w_body_C2_26';
UPDATE words SET example_en_2 = 'Laughter triggers the release of endorphins in the brain.', example_ko_2 = '웃음은 뇌에서 엔도르핀 분비를 유발해요.', example_en_3 = 'Endorphins act as natural painkillers during intense exercise.', example_ko_3 = '엔도르핀은 격렬한 운동 중에 천연 진통제 역할을 해요.', example_en_4 = 'She relied on the natural endorphins from her daily walk.', example_ko_4 = '그녀는 매일 산책에서 나오는 천연 엔도르핀에 의존했어요.', example_en_5 = 'Dark chocolate is said to promote the release of endorphins.', example_ko_5 = '다크 초콜릿은 엔도르핀 분비를 촉진한다고 알려져 있어요.' WHERE id = 'w_body_C2_27';
UPDATE words SET example_en_2 = 'Proprioceptive feedback deteriorates with age but can be trained.', example_ko_2 = '고유감각 피드백은 나이가 들면서 저하되지만 훈련할 수 있어요.', example_en_3 = 'Injury can disrupt proprioceptive feedback to the brain.', example_ko_3 = '부상은 뇌로 향하는 고유감각 피드백을 방해할 수 있어요.', example_en_4 = 'Rehabilitation exercises aim to restore proprioceptive feedback.', example_ko_4 = '재활 운동은 고유감각 피드백을 회복하는 것을 목표로 해요.', example_en_5 = 'She relied on proprioceptive feedback to land safely after jumps.', example_ko_5 = '그녀는 점프 후 안전하게 착지하기 위해 고유감각 피드백에 의존했어요.' WHERE id = 'w_body_C2_28';
UPDATE words SET example_en_2 = 'The somatosensory system integrates touch signals from the whole body.', example_ko_2 = '체감각 계통은 전신의 촉감 신호를 통합해요.', example_en_3 = 'He had reduced somatosensory sensitivity in his left hand.', example_ko_3 = '그는 왼손의 체감각 민감도가 감소했어요.', example_en_4 = 'The somatosensory cortex creates a map of the body''s surface.', example_ko_4 = '체감각 피질은 신체 표면의 지도를 만들어요.', example_en_5 = 'Chronic pain can alter somatosensory processing in the brain.', example_ko_5 = '만성 통증은 뇌의 체감각 처리 방식을 바꿀 수 있어요.' WHERE id = 'w_body_C2_29';
UPDATE words SET example_en_2 = 'Interoception includes sensing hunger, thirst, and heartbeat.', example_ko_2 = '내수용 감각에는 배고픔, 갈증, 심박수 감지가 포함돼요.', example_en_3 = 'Poor interoception may make it harder to recognise emotions.', example_ko_3 = '내수용 감각이 약하면 감정을 인식하기 더 어려울 수 있어요.', example_en_4 = 'Mindfulness practice strengthens interoceptive awareness.', example_ko_4 = '마음챙김 수련은 내수용 인식을 강화해요.', example_en_5 = 'She studied interoception as part of her research on eating disorders.', example_ko_5 = '그녀는 섭식 장애 연구의 일환으로 내수용 감각을 연구했어요.' WHERE id = 'w_body_C2_30';
UPDATE words SET example_en_2 = 'Nociceptors in the joints warn the brain of potential damage.', example_ko_2 = '관절의 침해수용기는 잠재적 손상을 뇌에 경고해요.', example_en_3 = 'Activated nociceptors send pain signals to the spinal cord.', example_ko_3 = '활성화된 침해수용기는 척수에 통증 신호를 보내요.', example_en_4 = 'Inflammation makes nociceptors more sensitive to stimuli.', example_ko_4 = '염증은 침해수용기가 자극에 더 민감하게 만들어요.', example_en_5 = 'The researcher studied how nociceptors respond to extreme cold.', example_ko_5 = '연구자는 침해수용기가 극심한 추위에 어떻게 반응하는지 연구했어요.' WHERE id = 'w_body_C2_31';
UPDATE words SET example_en_2 = 'Mechanoreceptors in the ear help detect sound vibrations.', example_ko_2 = '귀의 기계수용기는 소리 진동을 감지하는 데 도움이 돼요.', example_en_3 = 'Different mechanoreceptors respond to different types of pressure.', example_ko_3 = '서로 다른 기계수용기는 서로 다른 종류의 압력에 반응해요.', example_en_4 = 'She studied the distribution of mechanoreceptors in the palm.', example_ko_4 = '그녀는 손바닥의 기계수용기 분포를 연구했어요.', example_en_5 = 'Mechanoreceptors in the skin detect even the lightest touch.', example_ko_5 = '피부의 기계수용기는 가장 가벼운 접촉도 감지해요.' WHERE id = 'w_body_C2_32';
UPDATE words SET example_en_2 = 'Thermoreceptors in the mouth detect the temperature of food.', example_ko_2 = '입안의 열수용기는 음식의 온도를 감지해요.', example_en_3 = 'She felt immediate discomfort when the thermoreceptors activated.', example_ko_3 = '열수용기가 활성화되자 그녀는 즉각적인 불편함을 느꼈어요.', example_en_4 = 'Thermoreceptors help the body adapt to environmental temperature.', example_ko_4 = '열수용기는 신체가 환경 온도에 적응하는 데 도움이 돼요.', example_en_5 = 'The density of thermoreceptors varies across different body regions.', example_ko_5 = '열수용기의 밀도는 신체 부위마다 달라요.' WHERE id = 'w_body_C2_33';
UPDATE words SET example_en_2 = 'Chemoreceptors in the blood monitor oxygen and carbon dioxide levels.', example_ko_2 = '혈액의 화학수용기는 산소와 이산화탄소 수치를 감시해요.', example_en_3 = 'She studied how chemoreceptors contribute to breathing regulation.', example_ko_3 = '그녀는 화학수용기가 호흡 조절에 어떻게 기여하는지 연구했어요.', example_en_4 = 'Taste buds contain chemoreceptors that detect flavour molecules.', example_ko_4 = '미뢰에는 풍미 분자를 감지하는 화학수용기가 있어요.', example_en_5 = 'Certain chemoreceptors respond only to bitter or toxic substances.', example_ko_5 = '특정 화학수용기는 쓴맛이나 독성 물질에만 반응해요.' WHERE id = 'w_body_C2_34';
UPDATE words SET example_en_2 = 'The vestibulo-ocular reflex keeps images stable during movement.', example_ko_2 = '전정-안구 반사는 움직임 중 이미지를 안정적으로 유지해요.', example_en_3 = 'Damage to the inner ear can disrupt the vestibulo-ocular reflex.', example_ko_3 = '내이 손상은 전정-안구 반사를 방해할 수 있어요.', example_en_4 = 'The vestibulo-ocular reflex is tested by asking patients to track an object.', example_ko_4 = '전정-안구 반사는 환자에게 물체를 추적하도록 요청하여 검사해요.', example_en_5 = 'Athletes train to maintain an accurate vestibulo-ocular reflex.', example_ko_5 = '운동선수들은 정확한 전정-안구 반사를 유지하기 위해 훈련해요.' WHERE id = 'w_body_C2_35';

