UPDATE words SET example_en_2 = 'Their relationship grew stronger after going through hard times together.', example_ko_2 = '그들의 관계는 힘든 시간을 함께 겪으면서 더 강해졌어요.', example_en_3 = 'She tries to maintain a healthy relationship with all her relatives.', example_ko_3 = '그녀는 모든 친척들과 건강한 관계를 유지하려고 노력해요.', example_en_4 = 'A long-distance relationship requires a lot of trust and communication.', example_ko_4 = '장거리 관계는 많은 신뢰와 소통이 필요해요.', example_en_5 = 'The relationship between parents and children changes as children grow up.', example_ko_5 = '자녀가 성장하면서 부모와 자녀 사이의 관계가 달라져요.' WHERE id = 'w_family_B1_01';
UPDATE words SET example_en_2 = 'She admires her parents'' commitment to each other over forty years.', example_ko_2 = '그녀는 40년에 걸친 부모님의 서로에 대한 헌신을 존경해요.', example_en_3 = 'Raising children requires total commitment from both parents.', example_ko_3 = '자녀를 양육하는 것은 두 부모 모두의 완전한 헌신이 필요해요.', example_en_4 = 'His commitment to his family never wavered even during difficult times.', example_ko_4 = '힘든 시기에도 그의 가족에 대한 헌신은 흔들리지 않았어요.', example_en_5 = 'She made a commitment to spend more quality time with her children.', example_ko_5 = '그녀는 자녀들과 더 많은 양질의 시간을 보내겠다고 결심했어요.' WHERE id = 'w_family_B1_02';
UPDATE words SET example_en_2 = 'She moved out at twenty to experience her own independence.', example_ko_2 = '그녀는 자신의 독립을 경험하기 위해 스무 살에 독립했어요.', example_en_3 = 'Building independence in children starts with small responsibilities at home.', example_ko_3 = '자녀의 독립심 키우기는 가정에서의 작은 책임감에서 시작돼요.', example_en_4 = 'After the divorce, she valued her independence more than ever.', example_ko_4 = '이혼 후 그녀는 그 어느 때보다 독립을 소중히 여겼어요.', example_en_5 = 'Healthy families encourage independence while staying emotionally connected.', example_ko_5 = '건강한 가족은 정서적으로 연결을 유지하면서 독립을 장려해요.' WHERE id = 'w_family_B1_03';
UPDATE words SET example_en_2 = 'The conflict between father and son lasted for many years.', example_ko_2 = '부자 사이의 갈등은 수년간 지속됐어요.', example_en_3 = 'She learned to handle conflict calmly from her parents.', example_ko_3 = '그녀는 부모님에게서 갈등을 침착하게 다루는 법을 배웠어요.', example_en_4 = 'Avoiding conflict often makes family problems worse over time.', example_ko_4 = '갈등을 피하면 시간이 지나면서 가족 문제가 더 악화되는 경우가 많아요.', example_en_5 = 'They went to family counseling to work through their conflict.', example_ko_5 = '그들은 갈등을 해결하기 위해 가족 상담을 받으러 갔어요.' WHERE id = 'w_family_B1_04';
UPDATE words SET example_en_2 = 'She hoped her children would reconcile before it was too late.', example_ko_2 = '그녀는 너무 늦기 전에 자녀들이 화해하기를 바랐어요.', example_en_3 = 'They finally reconciled after a long and painful estrangement.', example_ko_3 = '그들은 길고 고통스러운 소원함 끝에 마침내 화해했어요.', example_en_4 = 'It is never too late to reconcile with a family member.', example_ko_4 = '가족과 화해하기에 늦은 때는 없어요.', example_en_5 = 'Reconciling with her sister was one of the best decisions she ever made.', example_ko_5 = '언니와 화해하는 것은 그녀가 한 가장 좋은 결정 중 하나였어요.' WHERE id = 'w_family_B1_05';
