UPDATE words SET example_en_2 = 'She practiced great patience when her toddler was upset.', example_ko_2 = '그녀는 유아가 속상해할 때 큰 인내심을 발휘했어요.', example_en_3 = 'Learning patience is one of the biggest lessons of parenthood.', example_ko_3 = '인내심을 배우는 것은 부모가 되는 것의 가장 큰 교훈 중 하나예요.', example_en_4 = 'He showed remarkable patience while caring for his elderly mother.', example_ko_4 = '그는 연로하신 어머니를 돌보면서 놀라운 인내심을 보여줬어요.', example_en_5 = 'Patience within a family makes difficult conversations easier.', example_ko_5 = '가족 내의 인내심은 어려운 대화를 더 쉽게 만들어줘요.' WHERE id = 'w_family_B1_15';
