UPDATE words SET example_en_2 = 'He learned to cook simple meals when he was a student.', example_ko_2 = '그는 학생 때 간단한 식사를 요리하는 법을 배웠어요.', example_en_3 = 'It takes about twenty minutes to cook this dish.', example_ko_3 = '이 요리를 만드는 데 약 20분이 걸려요.', example_en_4 = 'My mother taught me how to cook when I was young.', example_ko_4 = '어머니께서 어릴 때 요리하는 법을 가르쳐 주셨어요.', example_en_5 = 'Would you like to cook dinner together tonight?', example_ko_5 = '오늘 저녁에 같이 저녁을 만들어 볼까요?' WHERE id = 'w_cooking_A1_01';

UPDATE words SET example_en_2 = 'I found a great recipe for chocolate cake online.', example_ko_2 = '온라인에서 초콜릿 케이크 조리법을 발견했어요.', example_en_3 = 'This recipe requires only five ingredients.', example_ko_3 = '이 조리법에는 재료가 다섯 가지만 필요해요.', example_en_4 = 'She wrote the recipe down in her notebook.', example_ko_4 = '그녀는 조리법을 노트에 적어 두었어요.', example_en_5 = 'The recipe says to bake it for thirty minutes.', example_ko_5 = '조리법에는 30분 동안 굽는다고 나와 있어요.' WHERE id = 'w_cooking_A1_02';

UPDATE words SET example_en_2 = 'Always check that you have every ingredient before you start cooking.', example_ko_2 = '요리를 시작하기 전에 모든 재료가 있는지 확인하세요.', example_en_3 = 'Salt is an ingredient that almost every dish needs.', example_ko_3 = '소금은 거의 모든 요리에 필요한 재료예요.', example_en_4 = 'She bought the ingredients at the supermarket this morning.', example_ko_4 = '그녀는 오늘 아침 슈퍼마켓에서 재료를 샀어요.', example_en_5 = 'Fresh ingredients make the food taste much better.', example_ko_5 = '신선한 재료를 사용하면 음식이 훨씬 맛있어요.' WHERE id = 'w_cooking_A1_03';

UPDATE words SET example_en_2 = 'Tropical fruit is very sweet and full of vitamins.', example_ko_2 = '열대 과일은 매우 달콤하고 비타민이 풍부해요.', example_en_3 = 'He eats a piece of fruit after every meal.', example_ko_3 = '그는 매 식사 후에 과일을 한 조각 먹어요.', example_en_4 = 'We need to buy more fruit from the market today.', example_ko_4 = '오늘 시장에서 과일을 더 사야 해요.', example_en_5 = 'Which fruit do you like best—apples or oranges?', example_ko_5 = '사과와 오렌지 중 어떤 과일을 더 좋아하세요?' WHERE id = 'w_cooking_A1_04';

UPDATE words SET example_en_2 = 'Eating more vegetables is good for your health.', example_ko_2 = '채소를 더 많이 먹으면 건강에 좋아요.', example_en_3 = 'She grills vegetables on the barbecue every summer.', example_ko_3 = '그녀는 매년 여름 바비큐에서 채소를 구워요.', example_en_4 = 'What vegetables do you usually put in your soup?', example_ko_4 = '수프에 보통 어떤 채소를 넣으세요?', example_en_5 = 'Fresh vegetables from the garden taste amazing.', example_ko_5 = '텃밭에서 딴 신선한 채소는 정말 맛있어요.' WHERE id = 'w_cooking_A1_05';

UPDATE words SET example_en_2 = 'She prefers chicken over red meat.', example_ko_2 = '그녀는 붉은 고기보다 닭고기를 더 좋아해요.', example_en_3 = 'The meat was so tender it fell off the bone.', example_ko_3 = '고기가 너무 부드러워서 뼈에서 떨어졌어요.', example_en_4 = 'He buys fresh meat from the butcher every week.', example_ko_4 = '그는 매주 정육점에서 신선한 고기를 사요.', example_en_5 = 'Always cook meat thoroughly to avoid food poisoning.', example_ko_5 = '식중독을 예방하려면 고기를 항상 완전히 익혀 주세요.' WHERE id = 'w_cooking_A1_06';

UPDATE words SET example_en_2 = 'Salmon is a popular fish that is rich in omega-3.', example_ko_2 = '연어는 오메가-3가 풍부한 인기 있는 생선이에요.', example_en_3 = 'She grilled the fish with lemon and herbs.', example_ko_3 = '그녀는 레몬과 허브를 곁들여 생선을 구웠어요.', example_en_4 = 'I prefer fish to meat for dinner.', example_ko_4 = '저는 저녁으로 고기보다 생선을 더 좋아해요.', example_en_5 = 'The fish soup smells delicious from the kitchen.', example_ko_5 = '주방에서 생선 수프 냄새가 정말 맛있게 나요.' WHERE id = 'w_cooking_A1_07';

UPDATE words SET example_en_2 = 'Rice is the main staple food in many Asian countries.', example_ko_2 = '쌀은 많은 아시아 국가의 주요 주식이에요.', example_en_3 = 'He always adds a little salt when cooking rice.', example_ko_3 = '그는 쌀을 지을 때 항상 소금을 조금 넣어요.', example_en_4 = 'Can you serve me a second bowl of rice, please?', example_ko_4 = '밥을 한 그릇 더 주실 수 있을까요?', example_en_5 = 'Leftover rice can be used to make fried rice the next day.', example_ko_5 = '남은 밥은 다음 날 볶음밥을 만드는 데 쓸 수 있어요.' WHERE id = 'w_cooking_A1_08';

UPDATE words SET example_en_2 = 'She toasts the bread before spreading butter on it.', example_ko_2 = '그녀는 버터를 바르기 전에 빵을 구워요.', example_en_3 = 'This bread was baked fresh this morning.', example_ko_3 = '이 빵은 오늘 아침에 갓 구운 거예요.', example_en_4 = 'He makes his own bread every weekend.', example_ko_4 = '그는 매주 주말에 직접 빵을 만들어요.', example_en_5 = 'The bakery sells different types of bread every day.', example_ko_5 = '그 빵집은 매일 다양한 종류의 빵을 팔아요.' WHERE id = 'w_cooking_A1_09';

UPDATE words SET example_en_2 = 'Beat two eggs together with the milk.', example_ko_2 = '달걀 두 개를 우유와 함께 잘 풀어 주세요.', example_en_3 = 'She made a perfect omelette with three eggs.', example_ko_3 = '그녀는 달걀 세 개로 완벽한 오믈렛을 만들었어요.', example_en_4 = 'A boiled egg is a quick and healthy breakfast option.', example_ko_4 = '삶은 달걀은 빠르고 건강한 아침 식사예요.', example_en_5 = 'The recipe calls for two eggs at room temperature.', example_ko_5 = '조리법에는 실온의 달걀 두 개가 필요해요.' WHERE id = 'w_cooking_A1_10';

