UPDATE words SET example_en_2 = 'She studied French cuisine at a culinary school in Paris.', example_ko_2 = '그녀는 파리의 요리 학교에서 프랑스 요리를 공부했어요.', example_en_3 = 'Japanese cuisine is known for its simplicity and precision.', example_ko_3 = '일본 요리는 단순함과 정밀함으로 알려져 있어요.', example_en_4 = 'He explored the local cuisine during his travels in Southeast Asia.', example_ko_4 = '그는 동남아시아 여행 중 현지 요리를 탐색했어요.', example_en_5 = 'Italian cuisine places great emphasis on fresh, quality ingredients.', example_ko_5 = '이탈리아 요리는 신선하고 질 좋은 재료를 매우 중요하게 여겨요.' WHERE id = 'w_cooking_B2_01';

UPDATE words SET example_en_2 = 'He attended a culinary school to become a professional chef.', example_ko_2 = '그는 전문 요리사가 되기 위해 요리 학교에 다녔어요.', example_en_3 = 'Her culinary skills improve every time she practises.', example_ko_3 = '그녀는 연습할 때마다 요리 실력이 향상돼요.', example_en_4 = 'The culinary tradition of this region goes back centuries.', example_ko_4 = '이 지역의 요리 전통은 수백 년을 거슬러 올라가요.', example_en_5 = 'Culinary arts combine creativity with technical skill.', example_ko_5 = '요리는 창의성과 기술력이 결합된 예술이에요.' WHERE id = 'w_cooking_B2_02';

UPDATE words SET example_en_2 = 'She practised the knife technique until it became effortless.', example_ko_2 = '그녀는 칼 다루는 기술이 자연스러워질 때까지 연습했어요.', example_en_3 = 'Mastering the braising technique takes time and patience.', example_ko_3 = '브레이징 기술을 익히는 데는 시간과 인내가 필요해요.', example_en_4 = 'He learned classic French technique at cooking school.', example_ko_4 = '그는 요리 학교에서 프랑스 전통 기법을 배웠어요.', example_en_5 = 'Good cooking technique can elevate even the simplest ingredients.', example_ko_5 = '좋은 요리 기법은 가장 단순한 재료도 훌륭하게 만들 수 있어요.' WHERE id = 'w_cooking_B2_03';

UPDATE words SET example_en_2 = 'The chef focused on the presentation to impress the judges.', example_ko_2 = '그 요리사는 심사위원들에게 좋은 인상을 주기 위해 플레이팅에 집중했어요.', example_en_3 = 'Beautiful presentation makes a meal feel more special.', example_ko_3 = '아름다운 플레이팅은 식사를 더욱 특별하게 느끼게 해 줘요.', example_en_4 = 'She paid attention to the presentation of every dish she served.', example_ko_4 = '그녀는 내놓는 모든 요리의 플레이팅에 신경을 썼어요.', example_en_5 = 'Colour and height are key elements of good presentation.', example_ko_5 = '색감과 높이는 좋은 플레이팅의 핵심 요소예요.' WHERE id = 'w_cooking_B2_04';

UPDATE words SET example_en_2 = 'He studied plating techniques to make his dishes look professional.', example_ko_2 = '그는 요리를 전문적으로 보이게 하기 위해 플레이팅 기술을 배웠어요.', example_en_3 = 'Plating with tweezers allows for very precise presentation.', example_ko_3 = '핀셋으로 플레이팅하면 매우 정밀한 표현이 가능해요.', example_en_4 = 'She practised plating by watching videos of top chefs.', example_ko_4 = '그녀는 유명 요리사들의 영상을 보며 플레이팅을 연습했어요.', example_en_5 = 'The plating of each course was described as a work of art.', example_ko_5 = '각 코스의 플레이팅은 예술 작품이라고 불렸어요.' WHERE id = 'w_cooking_B2_05';

UPDATE words SET example_en_2 = 'She added a garnish of fresh dill to the smoked salmon.', example_ko_2 = '그녀는 훈제 연어에 신선한 딜로 가니시를 더했어요.', example_en_3 = 'A lemon twist is a classic garnish for fish dishes.', example_ko_3 = '레몬 트위스트는 생선 요리에 클래식한 가니시예요.', example_en_4 = 'He used edible flowers as a garnish on the dessert plate.', example_ko_4 = '그는 디저트 접시에 식용 꽃으로 가니시를 했어요.', example_en_5 = 'The garnish should complement the flavours of the dish.', example_ko_5 = '가니시는 요리의 풍미를 보완해야 해요.' WHERE id = 'w_cooking_B2_06';

UPDATE words SET example_en_2 = 'She made a red wine reduction to serve with the beef.', example_ko_2 = '그녀는 소고기와 함께 낼 레드 와인 리덕션을 만들었어요.', example_en_3 = 'A good reduction intensifies the flavour of the sauce.', example_ko_3 = '좋은 리덕션은 소스의 풍미를 더욱 진하게 해 줘요.', example_en_4 = 'He reduced the balsamic vinegar to a thick, syrupy glaze.', example_ko_4 = '그는 발사믹 식초를 걸쭉한 시럽 같은 글레이즈로 졸였어요.', example_en_5 = 'Let the stock reduction cool before drizzling over the dish.', example_ko_5 = '육수 리덕션을 식힌 뒤 요리 위에 뿌려 주세요.' WHERE id = 'w_cooking_B2_07';

UPDATE words SET example_en_2 = 'She caramelized onions slowly for forty minutes until golden.', example_ko_2 = '그녀는 양파가 황금빛이 될 때까지 40분 동안 천천히 캐러멜화했어요.', example_en_3 = 'The sugar will caramelize and turn a deep amber colour.', example_ko_3 = '설탕이 캐러멜화되면서 진한 호박색으로 변해요.', example_en_4 = 'He caramelized pears to serve on top of the cheesecake.', example_ko_4 = '그는 치즈케이크 위에 올릴 배를 캐러멜화했어요.', example_en_5 = 'You can caramelize almost any vegetable over low heat.', example_ko_5 = '거의 모든 채소를 약한 불에서 캐러멜화할 수 있어요.' WHERE id = 'w_cooking_B2_08';

UPDATE words SET example_en_2 = 'She deglazed the pan with white wine after searing the chicken.', example_ko_2 = '그녀는 닭고기를 지진 후 화이트 와인으로 팬을 데글라제했어요.', example_en_3 = 'Deglaze the pan to capture the delicious brown bits.', example_ko_3 = '팬을 데글라제해서 맛있는 갈색 찌꺼기를 활용해 주세요.', example_en_4 = 'He deglazed with brandy and then added cream.', example_ko_4 = '그는 브랜디로 데글라제한 다음 크림을 추가했어요.', example_en_5 = 'Use chicken stock to deglaze the pan for extra flavour.', example_ko_5 = '더 풍부한 맛을 위해 닭 육수로 팬을 데글라제해 주세요.' WHERE id = 'w_cooking_B2_09';

UPDATE words SET example_en_2 = 'She learned to emulsify oil and vinegar by whisking vigorously.', example_ko_2 = '그녀는 오일과 식초를 세차게 휘저어 유화시키는 법을 배웠어요.', example_en_3 = 'Mustard helps emulsify the dressing and keep it stable.', example_ko_3 = '머스터드는 드레싱을 유화시키고 안정적으로 유지하는 데 도움을 줘요.', example_en_4 = 'He used a hand blender to emulsify the sauce until smooth.', example_ko_4 = '그는 핸드 블렌더를 사용해 소스를 부드럽게 유화시켰어요.', example_en_5 = 'Egg yolk is a natural emulsifier used in many sauces.', example_ko_5 = '달걀 노른자는 많은 소스에 사용되는 천연 유화제예요.' WHERE id = 'w_cooking_B2_10';

UPDATE words SET example_en_2 = 'She poached the chicken breasts in seasoned broth.', example_ko_2 = '그녀는 닭 가슴살을 양념한 육수에서 포칭했어요.', example_en_3 = 'He poached the pears in spiced red wine.', example_ko_3 = '그는 향신료 레드 와인에서 배를 포칭했어요.', example_en_4 = 'Poach eggs at a gentle simmer for the best results.', example_ko_4 = '달걀은 살짝 끓는 물에서 포칭해야 가장 잘 돼요.', example_en_5 = 'Poached fish stays moist and retains its delicate flavour.', example_ko_5 = '포칭한 생선은 촉촉하고 섬세한 맛을 유지해요.' WHERE id = 'w_cooking_B2_11';

UPDATE words SET example_en_2 = 'She blanched the spinach for thirty seconds to preserve its colour.', example_ko_2 = '그녀는 색을 유지하기 위해 시금치를 30초 동안 데쳤어요.', example_en_3 = 'He blanched the almonds to make them easier to peel.', example_ko_3 = '그는 껍질을 벗기기 쉽도록 아몬드를 데쳤어요.', example_en_4 = 'Blanch the beans for two minutes and then refresh in ice water.', example_ko_4 = '콩을 2분 동안 데친 후 얼음물에 담가 식혀 주세요.', example_en_5 = 'Blanching preserves both the colour and texture of vegetables.', example_ko_5 = '데치면 채소의 색과 식감이 모두 보존돼요.' WHERE id = 'w_cooking_B2_12';

UPDATE words SET example_en_2 = 'She braised the lamb shank with red wine and rosemary.', example_ko_2 = '그녀는 양 정강이를 레드 와인과 로즈마리와 함께 끓여 익혔어요.', example_en_3 = 'Braising tougher cuts of meat makes them incredibly tender.', example_ko_3 = '질긴 부위를 브레이징하면 매우 부드러워져요.', example_en_4 = 'He braised the pork belly for three hours in soy sauce.', example_ko_4 = '그는 간장에 삼겹살을 세 시간 동안 브레이징했어요.', example_en_5 = 'Braised dishes are perfect for cold weather because they warm the body.', example_ko_5 = '브레이징 요리는 몸을 따뜻하게 해 주어 추운 날씨에 딱 맞아요.' WHERE id = 'w_cooking_B2_13';

UPDATE words SET example_en_2 = 'He performed a flambé at the table to impress the guests.', example_ko_2 = '그는 손님들에게 깊은 인상을 주기 위해 테이블에서 플람베를 선보였어요.', example_en_3 = 'She flambéed the bananas with rum for a classic dessert.', example_ko_3 = '그녀는 럼으로 바나나를 플람베해서 클래식 디저트를 만들었어요.', example_en_4 = 'The flambé technique burns off the alcohol while adding flavour.', example_ko_4 = '플람베 기법은 알코올을 태우면서 풍미를 더해 줘요.', example_en_5 = 'Always be very careful when you flambé—keep a lid nearby.', example_ko_5 = '플람베를 할 때는 뚜껑을 가까이 두고 매우 조심해야 해요.' WHERE id = 'w_cooking_B2_14';

UPDATE words SET example_en_2 = 'She learned to ferment her own vegetables at home.', example_ko_2 = '그녀는 집에서 직접 채소를 발효시키는 법을 배웠어요.', example_en_3 = 'Traditional soy sauce is made through a long fermentation process.', example_ko_3 = '전통 간장은 오랜 발효 과정을 통해 만들어져요.', example_en_4 = 'He ferments his own kimchi every autumn.', example_ko_4 = '그는 매년 가을에 직접 김치를 담가요.', example_en_5 = 'Fermented foods are great for gut health.', example_ko_5 = '발효 식품은 장 건강에 매우 좋아요.' WHERE id = 'w_cooking_B2_15';

UPDATE words SET example_en_2 = 'She learned to preserve tomatoes in olive oil for winter.', example_ko_2 = '그녀는 겨울을 위해 올리브 오일에 토마토를 보존하는 법을 배웠어요.', example_en_3 = 'He preserves seasonal fruits as jams and compotes.', example_ko_3 = '그는 제철 과일을 잼과 콩포트로 보존해요.', example_en_4 = 'Salt has been used to preserve meat and fish for centuries.', example_ko_4 = '소금은 수백 년 동안 고기와 생선을 보존하는 데 사용되어 왔어요.', example_en_5 = 'Preserving food at home is a satisfying skill to learn.', example_ko_5 = '집에서 식품을 보존하는 것은 배워 두면 만족스러운 기술이에요.' WHERE id = 'w_cooking_B2_16';

UPDATE words SET example_en_2 = 'She pickled cucumber and radish as a side dish.', example_ko_2 = '그녀는 오이와 무를 반찬으로 절였어요.', example_en_3 = 'He makes quick pickled onions in just thirty minutes.', example_ko_3 = '그는 30분 만에 빠른 피클 양파를 만들어요.', example_en_4 = 'Pickled vegetables add a sharp, acidic contrast to rich dishes.', example_ko_4 = '절인 채소는 진한 요리에 날카롭고 산뜻한 대비를 더해 줘요.', example_en_5 = 'She pickled green chillies in vinegar and salt.', example_ko_5 = '그녀는 식초와 소금에 청양고추를 절였어요.' WHERE id = 'w_cooking_B2_17';

UPDATE words SET example_en_2 = 'She cured the salmon with salt and dill for two days.', example_ko_2 = '그녀는 소금과 딜로 이틀 동안 연어를 절였어요.', example_en_3 = 'He cured the pork himself to make homemade bacon.', example_ko_3 = '그는 직접 돼지고기를 절여 집에서 베이컨을 만들었어요.', example_en_4 = 'Curing preserves the meat and deepens its flavour significantly.', example_ko_4 = '절이기는 고기를 보존하고 풍미를 크게 깊게 해 줘요.', example_en_5 = 'Cured meats are a staple of many European food traditions.', example_ko_5 = '염장 육류는 많은 유럽 음식 전통의 기본 요소예요.' WHERE id = 'w_cooking_B2_18';

