UPDATE words SET example_en_2 = 'She infused the cream with vanilla for the custard.', example_ko_2 = '그녀는 커스터드를 위해 크림에 바닐라를 우려냈어요.', example_en_3 = 'He infused olive oil with garlic and chilli for dipping.', example_ko_3 = '그는 찍어 먹기 위해 올리브 오일에 마늘과 고추를 우려냈어요.', example_en_4 = 'Infuse the tea for three to five minutes for the best flavour.', example_ko_4 = '최고의 맛을 위해 차를 3~5분 동안 우려내 주세요.', example_en_5 = 'Infusing herbs into butter creates a flavourful spread.', example_ko_5 = '허브를 버터에 우려내면 풍미 가득한 스프레드가 돼요.' WHERE id = 'w_cooking_B2_20';

UPDATE words SET example_en_2 = 'She judged the food first by its texture before its taste.', example_ko_2 = '그녀는 음식을 맛보기 전에 먼저 식감으로 평가했어요.', example_en_3 = 'Crunchy texture adds an enjoyable contrast to smooth sauces.', example_ko_3 = '바삭한 식감은 부드러운 소스에 즐거운 대비를 더해 줘요.', example_en_4 = 'He described the bread as having a wonderfully chewy texture.', example_ko_4 = '그는 빵의 식감이 훌륭하게 쫄깃하다고 표현했어요.', example_en_5 = 'The texture of the sauce was silky and smooth.', example_ko_5 = '소스의 질감은 실크처럼 부드러웠어요.' WHERE id = 'w_cooking_B2_21';

UPDATE words SET example_en_2 = 'The aroma of freshly baked bread filled the entire house.', example_ko_2 = '갓 구운 빵 향기가 온 집 안에 가득 찼어요.', example_en_3 = 'She described the aroma of the dish as warm and inviting.', example_ko_3 = '그녀는 요리의 향을 따뜻하고 매력적이라고 표현했어요.', example_en_4 = 'Adding fresh herbs at the end of cooking preserves their aroma.', example_ko_4 = '요리 마지막에 신선한 허브를 넣으면 향이 보존돼요.', example_en_5 = 'The aroma of roasting garlic is one of the most comforting smells.', example_ko_5 = '마늘 굽는 향기는 가장 편안함을 주는 냄새 중 하나예요.' WHERE id = 'w_cooking_B2_22';

UPDATE words SET example_en_2 = 'She added miso paste to boost the umami in the broth.', example_ko_2 = '그녀는 육수의 감칠맛을 높이기 위해 된장을 추가했어요.', example_en_3 = 'Parmesan cheese adds a strong umami flavour to pasta dishes.', example_ko_3 = '파르메산 치즈는 파스타 요리에 강한 감칠맛을 더해 줘요.', example_en_4 = 'He used anchovy paste to add depth of umami to the sauce.', example_ko_4 = '그는 소스에 감칠맛의 깊이를 더하기 위해 멸치 페이스트를 사용했어요.', example_en_5 = 'Umami is often described as the fifth basic taste.', example_ko_5 = '감칠맛은 흔히 다섯 번째 기본 맛으로 표현돼요.' WHERE id = 'w_cooking_B2_23';

UPDATE words SET example_en_2 = 'She loves the savory combination of cheese and rosemary in bread.', example_ko_2 = '그녀는 빵에 치즈와 로즈마리의 짭짤한 조합을 좋아해요.', example_en_3 = 'He prefers savory breakfasts like eggs and toast.', example_ko_3 = '그는 달걀과 토스트 같은 짭짤한 아침 식사를 즐겨요.', example_en_4 = 'The savory aroma of the roasting meat filled the kitchen.', example_ko_4 = '구워지는 고기의 구수한 향기가 주방을 가득 채웠어요.', example_en_5 = 'Savory dishes often go better with wine than sweet ones.', example_ko_5 = '짭짤한 요리는 단 것보다 와인과 더 잘 어울려요.' WHERE id = 'w_cooking_B2_24';

UPDATE words SET example_en_2 = 'Dark chocolate has a pleasantly bitter flavour.', example_ko_2 = '다크 초콜릿은 기분 좋게 쌉싸름한 맛이 나요.', example_en_3 = 'The bitter taste of coffee can be balanced with a little sugar.', example_ko_3 = '커피의 쓴맛은 설탕을 조금 넣으면 부드러워질 수 있어요.', example_en_4 = 'She added a pinch of salt to reduce the bitter taste.', example_ko_4 = '그녀는 쓴맛을 줄이기 위해 소금을 조금 넣었어요.', example_en_5 = 'Radicchio and endive are both pleasantly bitter salad leaves.', example_ko_5 = '라디키오와 엔다이브는 모두 기분 좋게 쌉싸름한 샐러드 잎이에요.' WHERE id = 'w_cooking_B2_25';

UPDATE words SET example_en_2 = 'She added a splash of lemon to increase the acidity.', example_ko_2 = '그녀는 산도를 높이기 위해 레몬을 조금 뿌렸어요.', example_en_3 = 'The acidity of the tomatoes balances the richness of the cream.', example_ko_3 = '토마토의 산도가 크림의 진한 맛을 잡아 줘요.', example_en_4 = 'He adjusted the acidity of the dressing with a pinch of sugar.', example_ko_4 = '그는 드레싱의 산도를 설탕 한 꼬집으로 조절했어요.', example_en_5 = 'Wines with higher acidity pair well with fatty foods.', example_ko_5 = '산도가 높은 와인은 기름진 음식과 잘 어울려요.' WHERE id = 'w_cooking_B2_26';

