UPDATE words SET example_en_2 = 'She created a contrast of textures with crispy skin and soft flesh.', example_ko_2 = '그녀는 바삭한 껍질과 부드러운 살로 식감의 대비를 만들었어요.', example_en_3 = 'The contrast between the cold ice cream and warm brownie is delightful.', example_ko_3 = '차가운 아이스크림과 따뜻한 브라우니의 대비가 정말 좋아요.', example_en_4 = 'He used fresh herbs as a contrast to the rich braised meat.', example_ko_4 = '그는 진하게 조린 고기의 대비로 신선한 허브를 사용했어요.', example_en_5 = 'A contrast of flavours makes a dish more interesting.', example_ko_5 = '풍미의 대비가 요리를 더욱 흥미롭게 만들어 줘요.' WHERE id = 'w_cooking_B2_28';

UPDATE words SET example_en_2 = 'She discovered wine and food pairing at a tasting event.', example_ko_2 = '그녀는 시음 행사에서 와인과 음식 페어링을 발견했어요.', example_en_3 = 'The classic pairing of bread and butter never fails.', example_ko_3 = '빵과 버터의 클래식한 페어링은 언제나 성공이에요.', example_en_4 = 'He explored new spice pairings in his weekend cooking experiments.', example_ko_4 = '그는 주말 요리 실험에서 새로운 향신료 페어링을 탐색했어요.', example_en_5 = 'The pairing of miso and butter is surprisingly delicious.', example_ko_5 = '된장과 버터의 페어링은 놀랍도록 맛있어요.' WHERE id = 'w_cooking_B2_29';

UPDATE words SET example_en_2 = 'The restaurant is known for its creative fusion menu.', example_ko_2 = '그 레스토랑은 창의적인 퓨전 메뉴로 유명해요.', example_en_3 = 'She created a fusion dish inspired by both Korean and Italian flavours.', example_ko_3 = '그녀는 한국과 이탈리아 풍미에서 영감을 받아 퓨전 요리를 만들었어요.', example_en_4 = 'Fusion cooking allows chefs to break traditional boundaries.', example_ko_4 = '퓨전 요리는 요리사들이 전통의 경계를 깰 수 있게 해 줘요.', example_en_5 = 'He opened a fusion restaurant combining French and Japanese cuisine.', example_ko_5 = '그는 프랑스와 일본 요리를 결합한 퓨전 레스토랑을 열었어요.' WHERE id = 'w_cooking_B2_30';

UPDATE words SET example_en_2 = 'She prefers artisan bread from the local bakery.', example_ko_2 = '그녀는 동네 빵집의 장인이 만든 빵을 더 좋아해요.', example_en_3 = 'Artisan cheese makers take years to perfect their craft.', example_ko_3 = '장인 치즈 제조자들은 기술을 완성하기까지 수년이 걸려요.', example_en_4 = 'He buys artisan pasta made in small batches by hand.', example_ko_4 = '그는 손으로 소량씩 만든 장인 파스타를 사요.', example_en_5 = 'Artisan products tend to cost more but the quality is much higher.', example_ko_5 = '장인 제품은 더 비싸지만 품질이 훨씬 높아요.' WHERE id = 'w_cooking_B2_31';

UPDATE words SET example_en_2 = 'She only buys sustainable seafood certified by eco-labels.', example_ko_2 = '그녀는 친환경 인증을 받은 지속 가능한 해산물만 구입해요.', example_en_3 = 'The restaurant introduced a sustainable menu using local produce.', example_ko_3 = '그 레스토랑은 현지 농산물을 활용한 지속 가능한 메뉴를 도입했어요.', example_en_4 = 'He supports sustainable farming by shopping at farmers'' markets.', example_ko_4 = '그는 농부 시장에서 쇼핑해 지속 가능한 농업을 지지해요.', example_en_5 = 'Choosing sustainable ingredients is good for the planet and our health.', example_ko_5 = '지속 가능한 재료를 선택하는 것은 지구와 우리 건강 모두에 좋아요.' WHERE id = 'w_cooking_B2_32';

UPDATE words SET example_en_2 = 'She only uses organic sourcing for the ingredients in her restaurant.', example_ko_2 = '그녀는 레스토랑의 식재료를 오직 유기농으로만 조달해요.', example_en_3 = 'The menu clearly states that all produce is from organic sourcing.', example_ko_3 = '메뉴에는 모든 농산물이 유기농으로 조달된다고 명시되어 있어요.', example_en_4 = 'He switched to organic sourcing after learning about pesticide risks.', example_ko_4 = '그는 살충제 위험성을 알고 나서 유기농 조달로 전환했어요.', example_en_5 = 'Organic sourcing ensures fewer chemicals in your food.', example_ko_5 = '유기농 조달을 하면 식품에 화학 물질이 더 적게 들어가요.' WHERE id = 'w_cooking_B2_33';

UPDATE words SET example_en_2 = 'The restaurant promotes a farm-to-table philosophy with local farmers.', example_ko_2 = '그 레스토랑은 현지 농부들과 함께 농장에서 식탁으로 이어지는 철학을 추구해요.', example_en_3 = 'Farm-to-table dining helps reduce the carbon footprint of meals.', example_ko_3 = '농장에서 식탁으로 이어지는 식사는 식사의 탄소 발자국을 줄이는 데 도움이 돼요.', example_en_4 = 'She started a farm-to-table catering business last year.', example_ko_4 = '그녀는 작년에 팜투테이블 케이터링 사업을 시작했어요.', example_en_5 = 'Farm-to-table ingredients are fresher because they travel less distance.', example_ko_5 = '팜투테이블 식재료는 이동 거리가 짧아 더 신선해요.' WHERE id = 'w_cooking_B2_34';

UPDATE words SET example_en_2 = 'She designed a zero waste menu that uses every part of the ingredient.', example_ko_2 = '그녀는 재료의 모든 부분을 활용하는 제로 웨이스트 메뉴를 설계했어요.', example_en_3 = 'Zero waste cooking encourages using vegetable tops and peelings.', example_ko_3 = '제로 웨이스트 요리는 채소 잎사귀와 껍질까지 활용하는 것을 장려해요.', example_en_4 = 'He committed to zero waste by composting all kitchen scraps.', example_ko_4 = '그는 주방 음식물 쓰레기를 모두 퇴비로 만들어 제로 웨이스트를 실천해요.', example_en_5 = 'A zero waste approach saves money as well as reducing waste.', example_ko_5 = '제로 웨이스트 접근법은 쓰레기를 줄이는 동시에 돈도 절약해 줘요.' WHERE id = 'w_cooking_B2_35';

-- C1
UPDATE words SET example_en_2 = 'She became passionate about gastronomy after a trip to Lyon.', example_ko_2 = '그녀는 리옹 여행 이후 미식학에 열정을 갖게 됐어요.', example_en_3 = 'Gastronomy explores the deep cultural connection between food and identity.', example_ko_3 = '미식학은 음식과 정체성 사이의 깊은 문화적 연결을 탐구해요.', example_en_4 = 'He studied gastronomy at a renowned institute in Spain.', example_ko_4 = '그는 스페인의 유명한 연구소에서 미식학을 공부했어요.', example_en_5 = 'Gastronomy is increasingly recognised as a serious academic discipline.', example_ko_5 = '미식학은 점점 더 진지한 학문 분야로 인정받고 있어요.' WHERE id = 'w_cooking_C1_01';

UPDATE words SET example_en_2 = 'She arrived an hour early to complete her mise en place before service.', example_ko_2 = '그녀는 서비스 전에 미장플라스를 완료하기 위해 한 시간 일찍 도착했어요.', example_en_3 = 'Good mise en place is the foundation of a smooth cooking service.', example_ko_3 = '좋은 미장플라스는 원활한 요리 서비스의 기초예요.', example_en_4 = 'He taught the students the importance of mise en place in a professional kitchen.', example_ko_4 = '그는 학생들에게 전문 주방에서 미장플라스의 중요성을 가르쳤어요.', example_en_5 = 'Mise en place reduces stress and speeds up the cooking process.', example_ko_5 = '미장플라스를 하면 스트레스가 줄고 요리 과정이 빨라져요.' WHERE id = 'w_cooking_C1_02';

UPDATE words SET example_en_2 = 'She julienned the carrots for a colourful salad garnish.', example_ko_2 = '그녀는 색감 있는 샐러드 가니시를 위해 당근을 채 썰었어요.', example_en_3 = 'Julienned vegetables cook faster because they are cut so thinly.', example_ko_3 = '채 썬 채소는 얇게 잘려 있어서 더 빨리 익어요.', example_en_4 = 'He practised his julienne cuts until every piece was uniform.', example_ko_4 = '그는 모든 조각이 균일해질 때까지 채 써는 연습을 했어요.', example_en_5 = 'Julienne the courgette and sauté it briefly in olive oil.', example_ko_5 = '애호박을 채 썰어 올리브 오일에 살짝 볶아 주세요.' WHERE id = 'w_cooking_C1_03';

UPDATE words SET example_en_2 = 'She used a brunoise of carrot and celery as a garnish.', example_ko_2 = '그녀는 당근과 셀러리 브뤼누아즈를 가니시로 사용했어요.', example_en_3 = 'Brunoise requires a very sharp knife and steady hands.', example_ko_3 = '브뤼누아즈를 하려면 매우 예리한 칼과 안정된 손이 필요해요.', example_en_4 = 'He started with julienne and then cut across to make a brunoise.', example_ko_4 = '그는 채 썰기를 먼저 한 다음 가로로 잘라 브뤼누아즈를 만들었어요.', example_en_5 = 'A fine brunoise is used to add texture to clear soups.', example_ko_5 = '맑은 수프에 식감을 더하기 위해 고운 브뤼누아즈를 사용해요.' WHERE id = 'w_cooking_C1_04';

UPDATE words SET example_en_2 = 'She chiffonaded fresh basil to finish the pasta dish.', example_ko_2 = '그녀는 파스타 요리를 마무리하기 위해 신선한 바질을 채 썰었어요.', example_en_3 = 'Chiffonade is the best way to cut large leafy herbs.', example_ko_3 = '시포나드는 큰 잎 허브를 써는 가장 좋은 방법이에요.', example_en_4 = 'He added a chiffonade of mint to the fruit salad.', example_ko_4 = '그는 과일 샐러드에 채 썬 민트를 얹었어요.', example_en_5 = 'Stack the basil leaves and roll them before cutting chiffonade.', example_ko_5 = '바질 잎을 쌓아 돌돌 만 다음 채 썰어 주세요.' WHERE id = 'w_cooking_C1_05';

UPDATE words SET example_en_2 = 'She made a roux with equal parts butter and flour.', example_ko_2 = '그녀는 버터와 밀가루를 같은 비율로 섞어 루를 만들었어요.', example_en_3 = 'A roux is the thickening base for many classic French sauces.', example_ko_3 = '루는 많은 클래식 프랑스 소스의 걸쭉한 베이스예요.', example_en_4 = 'He cooked the roux for two minutes to remove the raw flour taste.', example_ko_4 = '그는 날밀가루 맛을 없애기 위해 루를 2분 동안 볶았어요.', example_en_5 = 'A darker roux has a nuttier flavour than a pale one.', example_ko_5 = '더 진한 루는 연한 루보다 고소한 맛이 강해요.' WHERE id = 'w_cooking_C1_06';

UPDATE words SET example_en_2 = 'She made a classic velouté from chicken stock and a blonde roux.', example_ko_2 = '그녀는 닭 육수와 블론드 루로 클래식 벨루테를 만들었어요.', example_en_3 = 'Velouté is one of the five French mother sauces.', example_ko_3 = '벨루테는 프랑스의 다섯 가지 모체 소스 중 하나예요.', example_en_4 = 'He used a fish velouté as the base for a seafood bisque.', example_ko_4 = '그는 해산물 비스크의 베이스로 생선 벨루테를 사용했어요.', example_en_5 = 'Mastering velouté opens the door to many other classical sauces.', example_ko_5 = '벨루테를 익히면 다른 많은 고전 소스로 나아갈 수 있어요.' WHERE id = 'w_cooking_C1_07';

UPDATE words SET example_en_2 = 'She prepared béchamel for the lasagne the night before.', example_ko_2 = '그녀는 전날 밤에 라사냐용 베샤멜을 준비했어요.', example_en_3 = 'Béchamel sauce is the base for a classic macaroni cheese.', example_ko_3 = '베샤멜 소스는 클래식 맥앤치즈의 기초예요.', example_en_4 = 'He whisked the béchamel constantly to prevent lumps.', example_ko_4 = '그는 덩어리가 생기지 않도록 베샤멜을 계속 저었어요.', example_en_5 = 'Add nutmeg to béchamel for a warm, subtle flavour.', example_ko_5 = '베샤멜에 넛메그를 넣으면 은은하고 따뜻한 향이 나요.' WHERE id = 'w_cooking_C1_08';

UPDATE words SET example_en_2 = 'She uses espagnole as the base for her rich beef stew.', example_ko_2 = '그녀는 진한 소고기 스튜의 베이스로 에스파뇰을 사용해요.', example_en_3 = 'Espagnole is one of the most complex classical French sauces.', example_ko_3 = '에스파뇰은 가장 복잡한 프랑스 고전 소스 중 하나예요.', example_en_4 = 'Making espagnole from scratch takes several hours.', example_ko_4 = '에스파뇰을 처음부터 만드는 데는 몇 시간이 걸려요.', example_en_5 = 'Espagnole sauce is the foundation of many derivative sauces.', example_ko_5 = '에스파뇰 소스는 많은 파생 소스의 기초예요.' WHERE id = 'w_cooking_C1_09';

UPDATE words SET example_en_2 = 'She made hollandaise sauce by whisking egg yolks over gentle heat.', example_ko_2 = '그녀는 약한 불 위에서 달걀 노른자를 휘저어 홀랜다이즈 소스를 만들었어요.', example_en_3 = 'Hollandaise is traditionally served with eggs Benedict.', example_ko_3 = '홀랜다이즈는 전통적으로 에그 베네딕트와 함께 내요.', example_en_4 = 'He added tarragon to his hollandaise for a béarnaise variation.', example_ko_4 = '그는 베아르네즈 변형을 위해 홀랜다이즈에 타라곤을 넣었어요.', example_en_5 = 'Hollandaise sauce must be kept warm or it will separate.', example_ko_5 = '홀랜다이즈 소스는 따뜻하게 유지하지 않으면 분리될 수 있어요.' WHERE id = 'w_cooking_C1_10';

UPDATE words SET example_en_2 = 'She prepared a sous vide duck leg served with cherry sauce.', example_ko_2 = '그녀는 체리 소스를 곁들인 수비드 오리 다리 요리를 준비했어요.', example_en_3 = 'Sous vide cooking gives you precise control over temperature.', example_ko_3 = '수비드 요리는 온도를 정밀하게 제어할 수 있어요.', example_en_4 = 'He cooked the steak sous vide for two hours before searing.', example_ko_4 = '그는 스테이크를 굽기 전에 수비드로 두 시간 조리했어요.', example_en_5 = 'Sous vide ensures even cooking all the way through.', example_ko_5 = '수비드는 전체적으로 균일하게 익힐 수 있게 해 줘요.' WHERE id = 'w_cooking_C1_11';

UPDATE words SET example_en_2 = 'She made confit duck legs with thyme and bay leaves.', example_ko_2 = '그녀는 타임과 월계수 잎을 넣어 오리 다리 콩피를 만들었어요.', example_en_3 = 'Confit of garlic softens the cloves and mellows their flavour.', example_ko_3 = '마늘 콩피는 마늘 쪽을 부드럽게 하고 풍미를 순하게 해 줘요.', example_en_4 = 'He made duck confit and served it with lentils.', example_ko_4 = '그는 오리 콩피를 만들어 렌틸콩과 함께 냈어요.', example_en_5 = 'Confit is a method of slow cooking in fat at low temperature.', example_ko_5 = '콩피는 낮은 온도에서 기름에 천천히 익히는 조리 방법이에요.' WHERE id = 'w_cooking_C1_12';

UPDATE words SET example_en_2 = 'She made a classic country terrine with pork and herbs.', example_ko_2 = '그녀는 돼지고기와 허브로 클래식 컨트리 테린을 만들었어요.', example_en_3 = 'The terrine was sliced thinly and served with cornichons.', example_ko_3 = '테린을 얇게 썰어 코니숑과 함께 냈어요.', example_en_4 = 'He prepared a salmon terrine for the dinner party.', example_ko_4 = '그는 디너 파티를 위해 연어 테린을 준비했어요.', example_en_5 = 'A terrine must be chilled for several hours before slicing.', example_ko_5 = '테린은 자르기 전에 몇 시간 동안 차갑게 식혀야 해요.' WHERE id = 'w_cooking_C1_13';

UPDATE words SET example_en_2 = 'She made a classic Peruvian ceviche with lime and coriander.', example_ko_2 = '그녀는 라임과 고수로 클래식 페루식 세비체를 만들었어요.', example_en_3 = 'Ceviche is cured by the acid in citrus juice, not by heat.', example_ko_3 = '세비체는 열이 아닌 감귤류의 산으로 익혀요.', example_en_4 = 'He served ceviche with sweet potato and corn on the cob.', example_ko_4 = '그는 세비체를 고구마와 옥수수와 함께 냈어요.', example_en_5 = 'Fresh fish is essential for making safe and delicious ceviche.', example_ko_5 = '안전하고 맛있는 세비체를 만들려면 신선한 생선이 필수예요.' WHERE id = 'w_cooking_C1_14';

UPDATE words SET example_en_2 = 'She added a mirepoix of carrot, celery, and onion to the broth.', example_ko_2 = '그녀는 육수에 당근, 셀러리, 양파 미르푸아를 넣었어요.', example_en_3 = 'Mirepoix forms the flavour base of most soups and stews.', example_ko_3 = '미르푸아는 대부분의 수프와 스튜의 풍미 베이스를 형성해요.', example_en_4 = 'He sweated the mirepoix in butter before adding the stock.', example_ko_4 = '그는 육수를 넣기 전에 버터에 미르푸아를 천천히 볶았어요.', example_en_5 = 'A well-cooked mirepoix adds incredible depth to any dish.', example_ko_5 = '잘 볶은 미르푸아는 어떤 요리에도 놀라운 깊이를 더해 줘요.' WHERE id = 'w_cooking_C1_15';

UPDATE words SET example_en_2 = 'She tied together a bouquet garni with kitchen twine.', example_ko_2 = '그녀는 주방 끈으로 부케 가르니를 묶었어요.', example_en_3 = 'Remove the bouquet garni from the soup before serving.', example_ko_3 = '내기 전에 수프에서 부케 가르니를 꺼내 주세요.', example_en_4 = 'He made a classic bouquet garni with bay leaf, thyme, and parsley.', example_ko_4 = '그는 월계수 잎, 타임, 파슬리로 클래식 부케 가르니를 만들었어요.', example_en_5 = 'A bouquet garni flavours the dish without leaving herbs in it.', example_ko_5 = '부케 가르니는 허브가 남지 않으면서 요리에 풍미를 더해 줘요.' WHERE id = 'w_cooking_C1_16';

UPDATE words SET example_en_2 = 'She dehydrates tomatoes in the oven on a very low setting.', example_ko_2 = '그녀는 매우 낮은 온도에서 오븐에 토마토를 건조시켜요.', example_en_3 = 'He uses a dehydrator to dry herbs from his garden.', example_ko_3 = '그는 탈수기를 사용해 텃밭의 허브를 건조시켜요.', example_en_4 = 'Dehydrated fruit retains most of its nutrients and flavour.', example_ko_4 = '건조 과일은 대부분의 영양소와 풍미를 유지해요.', example_en_5 = 'Dehydrating vegetables concentrates their natural sweetness.', example_ko_5 = '채소를 건조시키면 자연스러운 단맛이 농축돼요.' WHERE id = 'w_cooking_C1_17';

UPDATE words SET example_en_2 = 'She learned spherification by practising with sodium alginate.', example_ko_2 = '그녀는 알긴산나트륨을 사용해 연습하며 구형화를 배웠어요.', example_en_3 = 'Spherification creates liquid-filled spheres that burst in the mouth.', example_ko_3 = '구형화는 입에서 터지는 액체로 채워진 구슬을 만들어요.', example_en_4 = 'He made olive oil spheres using a spherification kit.', example_ko_4 = '그는 구형화 키트를 사용해 올리브 오일 구슬을 만들었어요.', example_en_5 = 'Spherification is a popular technique in molecular gastronomy.', example_ko_5 = '구형화는 분자 요리학에서 인기 있는 기법이에요.' WHERE id = 'w_cooking_C1_18';

UPDATE words SET example_en_2 = 'She made a stable emulsion using a hand blender and oil.', example_ko_2 = '그녀는 핸드 블렌더와 오일로 안정적인 에멀션을 만들었어요.', example_en_3 = 'Mayonnaise is a classic example of an oil-in-water emulsion.', example_ko_3 = '마요네즈는 수중유 에멀션의 클래식한 예예요.', example_en_4 = 'He added lecithin to stabilise the emulsion.', example_ko_4 = '그는 에멀션을 안정시키기 위해 레시틴을 추가했어요.', example_en_5 = 'The emulsion broke because the oil was added too quickly.', example_ko_5 = '오일을 너무 빨리 넣어서 에멀션이 분리됐어요.' WHERE id = 'w_cooking_C1_19';

UPDATE words SET example_en_2 = 'She created a light foam from miso broth using a hand blender.', example_ko_2 = '그녀는 핸드 블렌더로 된장 육수로 가벼운 폼을 만들었어요.', example_en_3 = 'The foam dissolved too quickly and was gone before the dish arrived.', example_ko_3 = '폼이 너무 빨리 사라져서 요리가 도착하기 전에 없어졌어요.', example_en_4 = 'He used soy lecithin to create a stable foam.', example_ko_4 = '그는 안정적인 폼을 만들기 위해 대두 레시틴을 사용했어요.', example_en_5 = 'A flavoured foam can add drama to a dish without adding bulk.', example_ko_5 = '향이 있는 폼은 부피를 늘리지 않고도 요리에 극적인 효과를 줄 수 있어요.' WHERE id = 'w_cooking_C1_20';

UPDATE words SET example_en_2 = 'She used agar-agar to make a firm gel for the dessert.', example_ko_2 = '그녀는 디저트를 위해 단단한 겔을 만드는 데 한천을 사용했어요.', example_en_3 = 'The gel held its shape perfectly even after being sliced.', example_ko_3 = '겔은 잘라도 완벽하게 모양을 유지했어요.', example_en_4 = 'He created a fruit juice gel to garnish the cocktail dessert.', example_ko_4 = '그는 칵테일 디저트를 장식하기 위해 과일 주스 겔을 만들었어요.', example_en_5 = 'Gelatin and agar are both used to make gel-based dishes.', example_ko_5 = '젤라틴과 한천 모두 겔 기반 음식을 만드는 데 사용돼요.' WHERE id = 'w_cooking_C1_21';

UPDATE words SET example_en_2 = 'She studied molecular gastronomy to push the boundaries of cooking.', example_ko_2 = '그녀는 요리의 한계를 넓히기 위해 분자 요리학을 공부했어요.', example_en_3 = 'Molecular gastronomy applies science to create surprising food experiences.', example_ko_3 = '분자 요리학은 과학을 적용해 놀라운 음식 경험을 만들어요.', example_en_4 = 'He attended a molecular gastronomy workshop at a food festival.', example_ko_4 = '그는 음식 축제에서 분자 요리학 워크숍에 참가했어요.', example_en_5 = 'Molecular gastronomy has influenced how chefs think about texture and flavour.', example_ko_5 = '분자 요리학은 요리사들이 식감과 풍미를 생각하는 방식에 영향을 미쳤어요.' WHERE id = 'w_cooking_C1_22';

UPDATE words SET example_en_2 = 'She uses anchovy paste and soy sauce for umami enhancement.', example_ko_2 = '그녀는 감칠맛 향상을 위해 멸치 페이스트와 간장을 사용해요.', example_en_3 = 'He added tomato paste for further umami enhancement.', example_ko_3 = '그는 감칠맛을 더 높이기 위해 토마토 페이스트를 넣었어요.', example_en_4 = 'Layering ingredients is a common technique for umami enhancement.', example_ko_4 = '재료를 겹겹이 쌓는 것은 감칠맛 향상에 쓰이는 일반적인 기법이에요.', example_en_5 = 'Umami enhancement is a key principle in many Asian cooking traditions.', example_ko_5 = '감칠맛 향상은 많은 아시아 요리 전통의 핵심 원리예요.' WHERE id = 'w_cooking_C1_23';

UPDATE words SET example_en_2 = 'She studied the Maillard reaction to understand why seared meat tastes so good.', example_ko_2 = '그녀는 지진 고기가 왜 맛있는지 이해하기 위해 마이야르 반응을 공부했어요.', example_en_3 = 'The Maillard reaction is responsible for the golden crust on bread.', example_ko_3 = '마이야르 반응이 빵의 황금빛 껍질을 만들어요.', example_en_4 = 'He explained the Maillard reaction to his cooking students.', example_ko_4 = '그는 요리 학생들에게 마이야르 반응을 설명했어요.', example_en_5 = 'High heat and low moisture are needed to trigger the Maillard reaction.', example_ko_5 = '마이야르 반응을 일으키려면 높은 온도와 낮은 수분이 필요해요.' WHERE id = 'w_cooking_C1_24';

UPDATE words SET example_en_2 = 'She understood that caramelization happens at temperatures above 160°C.', example_ko_2 = '그녀는 캐러멜화가 160°C 이상에서 일어난다는 것을 이해했어요.', example_en_3 = 'Caramelization gives roasted vegetables their beautiful brown colour.', example_ko_3 = '캐러멜화가 구운 채소에 아름다운 갈색을 줘요.', example_en_4 = 'He explained that caramelization is a non-enzymatic browning process.', example_ko_4 = '그는 캐러멜화가 비효소적 갈변 과정이라고 설명했어요.', example_en_5 = 'Controlled caramelization adds complexity and depth to desserts.', example_ko_5 = '조절된 캐러멜화는 디저트에 복합성과 깊이를 더해 줘요.' WHERE id = 'w_cooking_C1_25';

UPDATE words SET example_en_2 = 'She studied the thermodynamics of cooking for her food science degree.', example_ko_2 = '그녀는 식품 과학 학위를 위해 요리의 열역학을 공부했어요.', example_en_3 = 'Understanding the thermodynamics of cooking helps explain why food changes.', example_ko_3 = '요리의 열역학을 이해하면 음식이 왜 변하는지 설명하는 데 도움이 돼요.', example_en_4 = 'He applied the thermodynamics of cooking to optimise his baking results.', example_ko_4 = '그는 베이킹 결과를 최적화하기 위해 요리의 열역학을 적용했어요.', example_en_5 = 'The thermodynamics of cooking connects physics and flavour science.', example_ko_5 = '요리의 열역학은 물리학과 풍미 과학을 연결해요.' WHERE id = 'w_cooking_C1_26';

UPDATE words SET example_en_2 = 'She used maceration to soften dried fruit for her cake.', example_ko_2 = '그녀는 케이크를 위해 건과일을 부드럽게 만들려고 침지 기법을 사용했어요.', example_en_3 = 'He macerated the strawberries in sugar for an hour.', example_ko_3 = '그는 딸기를 설탕에 한 시간 동안 재웠어요.', example_en_4 = 'Maceration in wine adds complex flavours to meats.', example_ko_4 = '와인에 재우면 고기에 복합적인 풍미가 더해져요.', example_en_5 = 'Maceration draws out the natural juices from the fruit.', example_ko_5 = '침지 기법은 과일에서 자연적인 즙을 끌어내요.' WHERE id = 'w_cooking_C1_27';

UPDATE words SET example_en_2 = 'She learned how osmosis affects the texture of brined vegetables.', example_ko_2 = '그녀는 삼투압이 소금물에 절인 채소의 식감에 어떤 영향을 미치는지 배웠어요.', example_en_3 = 'Osmosis is why salt draws moisture out of vegetables.', example_ko_3 = '삼투압이 소금이 채소에서 수분을 끌어내는 이유예요.', example_en_4 = 'He explained osmosis to his students using a salting experiment.', example_ko_4 = '그는 소금 처리 실험으로 학생들에게 삼투압을 설명했어요.', example_en_5 = 'Understanding osmosis helps explain marinating and curing techniques.', example_ko_5 = '삼투압을 이해하면 재우기와 절이기 기법을 설명하는 데 도움이 돼요.' WHERE id = 'w_cooking_C1_28';

UPDATE words SET example_en_2 = 'She identified the key flavor compound that made the dish unique.', example_ko_2 = '그녀는 요리를 독특하게 만드는 핵심 풍미 화합물을 찾아냈어요.', example_en_3 = 'Each flavor compound contributes something different to the overall taste.', example_ko_3 = '각 풍미 화합물은 전체적인 맛에 각각 다른 기여를 해요.', example_en_4 = 'He studied how heat affects flavor compounds in spices.', example_ko_4 = '그는 열이 향신료의 풍미 화합물에 어떤 영향을 미치는지 연구했어요.', example_en_5 = 'Some flavor compounds are only released when food is cooked.', example_ko_5 = '일부 풍미 화합물은 음식을 조리할 때만 방출돼요.' WHERE id = 'w_cooking_C1_29';

UPDATE words SET example_en_2 = 'She described the volatile aroma of the truffle as earthy and complex.', example_ko_2 = '그녀는 트러플의 휘발성 향을 흙냄새가 나고 복합적이라고 표현했어요.', example_en_3 = 'Heat releases volatile aroma compounds that stimulate the appetite.', example_ko_3 = '열은 식욕을 자극하는 휘발성 향 화합물을 방출해요.', example_en_4 = 'He detected a volatile aroma of vanilla in the pastry cream.', example_ko_4 = '그는 파티시에 크림에서 바닐라의 휘발성 향을 감지했어요.', example_en_5 = 'Volatile aromas are what you smell before you even taste the food.', example_ko_5 = '휘발성 향은 음식을 맛보기도 전에 맡을 수 있는 냄새예요.' WHERE id = 'w_cooking_C1_30';

UPDATE words SET example_en_2 = 'She developed a very sensitive palate through years of professional tasting.', example_ko_2 = '그녀는 수년간의 전문 테이스팅을 통해 매우 예민한 미각을 발전시켰어요.', example_en_3 = 'His palate easily distinguishes between different varieties of olive oil.', example_ko_3 = '그의 미각은 올리브 오일의 다양한 종류를 쉽게 구별해요.', example_en_4 = 'Developing your palate takes time and regular tasting practice.', example_ko_4 = '미각을 발전시키는 데는 시간과 꾸준한 테이스팅 연습이 필요해요.', example_en_5 = 'A chef with a refined palate can detect even the smallest imbalance.', example_ko_5 = '세련된 미각을 가진 요리사는 아주 작은 불균형도 감지할 수 있어요.' WHERE id = 'w_cooking_C1_31';

UPDATE words SET example_en_2 = 'She works as a taster and specialises in sensory evaluation of olive oil.', example_ko_2 = '그녀는 테이스터로 일하며 올리브 오일의 관능 평가를 전문으로 해요.', example_en_3 = 'Sensory evaluation involves assessing aroma, texture, and taste together.', example_ko_3 = '관능 평가는 향, 식감, 맛을 함께 평가하는 것을 포함해요.', example_en_4 = 'He conducted a sensory evaluation panel for the new product launch.', example_ko_4 = '그는 신제품 출시를 위해 관능 평가 패널을 진행했어요.', example_en_5 = 'Sensory evaluation is used in both research and commercial food development.', example_ko_5 = '관능 평가는 연구와 상업적 식품 개발 모두에 사용돼요.' WHERE id = 'w_cooking_C1_32';

UPDATE words SET example_en_2 = 'She studied food science to understand why ingredients behave as they do.', example_ko_2 = '그녀는 재료들이 왜 그렇게 반응하는지 이해하기 위해 식품 과학을 공부했어요.', example_en_3 = 'Food science combines chemistry, biology, and engineering.', example_ko_3 = '식품 과학은 화학, 생물학, 공학을 결합해요.', example_en_4 = 'He applied food science principles to develop a lower-fat version of the recipe.', example_ko_4 = '그는 레시피의 저지방 버전을 개발하기 위해 식품 과학 원리를 적용했어요.', example_en_5 = 'Food science has transformed how we produce and preserve food today.', example_ko_5 = '식품 과학은 오늘날 우리가 음식을 생산하고 보존하는 방식을 변화시켰어요.' WHERE id = 'w_cooking_C1_33';

UPDATE words SET example_en_2 = 'She checked the nutritional profile of the dish before putting it on the menu.', example_ko_2 = '그녀는 요리를 메뉴에 올리기 전에 영양 성분을 확인했어요.', example_en_3 = 'The nutritional profile of whole grains is far superior to refined ones.', example_ko_3 = '통곡물의 영양 성분은 정제된 것보다 훨씬 우수해요.', example_en_4 = 'He analysed the nutritional profile to create a balanced meal plan.', example_ko_4 = '그는 균형 잡힌 식단을 만들기 위해 영양 성분을 분석했어요.', example_en_5 = 'Cooking methods can dramatically change the nutritional profile of food.', example_ko_5 = '조리 방법에 따라 식품의 영양 성분이 크게 달라질 수 있어요.' WHERE id = 'w_cooking_C1_34';

UPDATE words SET example_en_2 = 'She respects the culinary tradition of the region she works in.', example_ko_2 = '그녀는 자신이 일하는 지역의 요리 전통을 존중해요.', example_en_3 = 'Culinary tradition is passed down through generations within families.', example_ko_3 = '요리 전통은 가족 내에서 세대를 거쳐 전해져요.', example_en_4 = 'He blends modern technique with culinary tradition in his restaurant.', example_ko_4 = '그는 레스토랑에서 현대적인 기법과 요리 전통을 결합해요.', example_en_5 = 'Preserving culinary tradition is important for cultural identity.', example_ko_5 = '요리 전통을 보존하는 것은 문화적 정체성에 중요해요.' WHERE id = 'w_cooking_C1_35';

-- C2
UPDATE words SET example_en_2 = 'She performed an organoleptic assessment of the new olive oil.', example_ko_2 = '그녀는 새 올리브 오일에 대한 관능 평가를 실시했어요.', example_en_3 = 'Organoleptic properties include colour, smell, taste, and texture.', example_ko_3 = '관능적 특성에는 색, 냄새, 맛, 식감이 포함돼요.', example_en_4 = 'He described the organoleptic characteristics of each wine for the panel.', example_ko_4 = '그는 패널을 위해 각 와인의 관능적 특성을 설명했어요.', example_en_5 = 'Organoleptic testing is a key step in food product development.', example_ko_5 = '관능 테스팅은 식품 제품 개발의 핵심 단계예요.' WHERE id = 'w_cooking_C2_01';

UPDATE words SET example_en_2 = 'She studies the health effects of oleic acid in Mediterranean diets.', example_ko_2 = '그녀는 지중해 식단에서 올레산의 건강 효과를 연구해요.', example_en_3 = 'Oleic acid is the main fatty acid in olive oil.', example_ko_3 = '올레산은 올리브 오일의 주요 지방산이에요.', example_en_4 = 'High oleic acid content makes some oils more heat-stable for cooking.', example_ko_4 = '높은 올레산 함량은 일부 오일을 요리에 더 열 안정적으로 만들어요.', example_en_5 = 'He explained that oleic acid is a monounsaturated fatty acid.', example_ko_5 = '그는 올레산이 단불포화 지방산이라고 설명했어요.' WHERE id = 'w_cooking_C2_02';

UPDATE words SET example_en_2 = 'She discovered that anthocyanin gives blueberries their deep blue colour.', example_ko_2 = '그녀는 안토시아닌이 블루베리에 짙은 파란색을 준다는 것을 발견했어요.', example_en_3 = 'Foods rich in anthocyanin are associated with anti-inflammatory benefits.', example_ko_3 = '안토시아닌이 풍부한 식품은 항염증 효과와 관련이 있어요.', example_en_4 = 'He uses red cabbage as an anthocyanin-rich natural food colouring.', example_ko_4 = '그는 안토시아닌이 풍부한 천연 식용 색소로 적양배추를 사용해요.', example_en_5 = 'Anthocyanin levels in food can change depending on how it is cooked.', example_ko_5 = '식품 내 안토시아닌 수준은 조리 방법에 따라 변할 수 있어요.' WHERE id = 'w_cooking_C2_03';

UPDATE words SET example_en_2 = 'She chose ingredients high in polyphenol for their health benefits.', example_ko_2 = '그녀는 건강상의 이점 때문에 폴리페놀 함량이 높은 재료를 선택했어요.', example_en_3 = 'Polyphenol compounds are found in tea, wine, and dark chocolate.', example_ko_3 = '폴리페놀 화합물은 차, 와인, 다크 초콜릿에 들어 있어요.', example_en_4 = 'He explained that polyphenol acts as a natural preservative in some foods.', example_ko_4 = '그는 폴리페놀이 일부 식품에서 천연 방부제 역할을 한다고 설명했어요.', example_en_5 = 'Polyphenol content in berries decreases with prolonged cooking.', example_ko_5 = '베리류의 폴리페놀 함량은 장시간 조리하면 감소해요.' WHERE id = 'w_cooking_C2_04';

UPDATE words SET example_en_2 = 'She chose berries for their high antioxidant content.', example_ko_2 = '그녀는 높은 항산화 성분 함량 때문에 베리류를 선택했어요.', example_en_3 = 'Cooking at high temperatures can destroy antioxidant compounds.', example_ko_3 = '높은 온도에서 조리하면 항산화 화합물이 파괴될 수 있어요.', example_en_4 = 'He adds a handful of spinach to his smoothie for antioxidant benefits.', example_ko_4 = '그는 항산화 효과를 위해 스무디에 시금치 한 줌을 넣어요.', example_en_5 = 'Spices like turmeric and clove are exceptionally rich in antioxidants.', example_ko_5 = '강황과 정향 같은 향신료는 항산화 성분이 특히 풍부해요.' WHERE id = 'w_cooking_C2_05';

UPDATE words SET example_en_2 = 'She advises diabetic clients on foods with a low glycemic index.', example_ko_2 = '그녀는 당뇨 환자들에게 혈당 지수가 낮은 식품을 조언해요.', example_en_3 = 'The glycemic index of white bread is much higher than that of oats.', example_ko_3 = '흰 빵의 혈당 지수는 귀리보다 훨씬 높아요.', example_en_4 = 'He chose sweet potato over white potato for its lower glycemic index.', example_ko_4 = '그는 낮은 혈당 지수 때문에 일반 감자 대신 고구마를 선택했어요.', example_en_5 = 'Cooking method affects the glycemic index of certain foods.', example_ko_5 = '조리 방법은 특정 식품의 혈당 지수에 영향을 미쳐요.' WHERE id = 'w_cooking_C2_06';

UPDATE words SET example_en_2 = 'She studied lipid oxidation to understand how fats go rancid.', example_ko_2 = '그녀는 지방이 어떻게 산패되는지 이해하기 위해 지질 산화를 공부했어요.', example_en_3 = 'Lipid oxidation is accelerated by heat, light, and oxygen.', example_ko_3 = '지질 산화는 열, 빛, 산소에 의해 가속돼요.', example_en_4 = 'He stores oils in dark bottles to slow lipid oxidation.', example_ko_4 = '그는 지질 산화를 늦추기 위해 오일을 어두운 병에 보관해요.', example_en_5 = 'Antioxidants are often added to processed foods to prevent lipid oxidation.', example_ko_5 = '가공 식품에는 지질 산화를 방지하기 위해 항산화제가 첨가되는 경우가 많아요.' WHERE id = 'w_cooking_C2_07';

UPDATE words SET example_en_2 = 'She explains protein denaturation using the example of a fried egg.', example_ko_2 = '그녀는 달걀프라이를 예로 들어 단백질 변성을 설명해요.', example_en_3 = 'Protein denaturation begins at temperatures above 40°C.', example_ko_3 = '단백질 변성은 40°C 이상의 온도에서 시작돼요.', example_en_4 = 'He studied how acid causes protein denaturation in ceviche.', example_ko_4 = '그는 세비체에서 산이 어떻게 단백질 변성을 일으키는지 연구했어요.', example_en_5 = 'Understanding protein denaturation helps explain why meat changes texture when cooked.', example_ko_5 = '단백질 변성을 이해하면 왜 고기가 조리될 때 식감이 변하는지 설명할 수 있어요.' WHERE id = 'w_cooking_C2_08';

UPDATE words SET example_en_2 = 'She learned that starch gelatinization is what thickens sauces and gravies.', example_ko_2 = '그녀는 소스와 그레이비를 걸쭉하게 만드는 것이 전분 호화라는 것을 배웠어요.', example_en_3 = 'Starch gelatinization occurs when starch granules absorb water and swell.', example_ko_3 = '전분 호화는 전분 입자가 물을 흡수해 팽창할 때 일어나요.', example_en_4 = 'He used cornstarch, which undergoes starch gelatinization at a lower temperature.', example_ko_4 = '그는 더 낮은 온도에서 전분 호화가 일어나는 옥수수 전분을 사용했어요.', example_en_5 = 'Starch gelatinization explains why puddings become firm as they cool.', example_ko_5 = '전분 호화가 식으면서 푸딩이 굳어지는 이유를 설명해 줘요.' WHERE id = 'w_cooking_C2_09';

UPDATE words SET example_en_2 = 'She studied fermentation chemistry to better understand sourdough bread.', example_ko_2 = '그녀는 사워도우 빵을 더 잘 이해하기 위해 발효 화학을 공부했어요.', example_en_3 = 'Fermentation chemistry explains how yeast converts sugar to carbon dioxide.', example_ko_3 = '발효 화학은 효모가 설탕을 이산화탄소로 전환하는 방법을 설명해요.', example_en_4 = 'He applied fermentation chemistry to develop a new probiotic beverage.', example_ko_4 = '그는 새로운 프로바이오틱 음료를 개발하기 위해 발효 화학을 적용했어요.', example_en_5 = 'Understanding fermentation chemistry helps produce consistent results in bread baking.', example_ko_5 = '발효 화학을 이해하면 빵을 구울 때 일정한 결과를 얻는 데 도움이 돼요.' WHERE id = 'w_cooking_C2_10';

UPDATE words SET example_en_2 = 'She prevented enzymatic browning by coating the apple slices in lemon juice.', example_ko_2 = '그녀는 사과 조각에 레몬즙을 발라 효소적 갈변을 막았어요.', example_en_3 = 'Enzymatic browning is why cut potatoes turn grey when exposed to air.', example_ko_3 = '효소적 갈변이 자른 감자가 공기에 노출되면 회색으로 변하는 이유예요.', example_en_4 = 'He blanched the avocado briefly to slow enzymatic browning.', example_ko_4 = '그는 효소적 갈변을 늦추기 위해 아보카도를 잠깐 데쳤어요.', example_en_5 = 'Enzymatic browning affects the colour, flavour, and nutritional quality of food.', example_ko_5 = '효소적 갈변은 식품의 색, 풍미, 영양 품질에 영향을 미쳐요.' WHERE id = 'w_cooking_C2_11';

UPDATE words SET example_en_2 = 'She distinguished between enzymatic browning and non-enzymatic browning in her lecture.', example_ko_2 = '그녀는 강의에서 효소적 갈변과 비효소적 갈변을 구분하여 설명했어요.', example_en_3 = 'The Maillard reaction is the most important type of non-enzymatic browning.', example_ko_3 = '마이야르 반응은 가장 중요한 비효소적 갈변 유형이에요.', example_en_4 = 'He studied non-enzymatic browning to improve the shelf life of bakery products.', example_ko_4 = '그는 빵 제품의 유통 기한을 개선하기 위해 비효소적 갈변을 연구했어요.', example_en_5 = 'Non-enzymatic browning in baked goods produces both desirable colour and flavour.', example_ko_5 = '구운 식품의 비효소적 갈변은 바람직한 색과 풍미를 만들어요.' WHERE id = 'w_cooking_C2_12';

UPDATE words SET example_en_2 = 'She studied collagen hydrolysis to understand why braised meats become tender.', example_ko_2 = '그녀는 브레이징한 고기가 왜 부드러워지는지 이해하기 위해 콜라겐 가수분해를 공부했어요.', example_en_3 = 'Collagen hydrolysis converts tough connective tissue into soft gelatin.', example_ko_3 = '콜라겐 가수분해는 질긴 결합 조직을 부드러운 젤라틴으로 변환해요.', example_en_4 = 'He used long, slow cooking to promote collagen hydrolysis in the pork shoulder.', example_ko_4 = '그는 돼지 어깨살에서 콜라겐 가수분해를 촉진하기 위해 오래 천천히 익혔어요.', example_en_5 = 'Collagen hydrolysis is why well-made stock has a gelatinous texture when cold.', example_ko_5 = '콜라겐 가수분해가 잘 만든 육수가 식으면 젤리처럼 굳는 이유예요.' WHERE id = 'w_cooking_C2_13';

UPDATE words SET example_en_2 = 'She studied emulsification physics to better understand sauce stability.', example_ko_2 = '그녀는 소스 안정성을 더 잘 이해하기 위해 유화 물리학을 공부했어요.', example_en_3 = 'Emulsification physics explains why oil and vinegar dressings separate.', example_ko_3 = '유화 물리학은 왜 오일과 식초 드레싱이 분리되는지 설명해요.', example_en_4 = 'He applied emulsification physics when formulating a new salad dressing product.', example_ko_4 = '그는 새 샐러드 드레싱 제품을 만들 때 유화 물리학을 적용했어요.', example_en_5 = 'Understanding emulsification physics helps chefs create stable sauces.', example_ko_5 = '유화 물리학을 이해하면 요리사가 안정적인 소스를 만드는 데 도움이 돼요.' WHERE id = 'w_cooking_C2_14';

UPDATE words SET example_en_2 = 'She used a surfactant to stabilise the foam in her molecular dessert.', example_ko_2 = '그녀는 분자 디저트의 폼을 안정시키기 위해 계면활성제를 사용했어요.', example_en_3 = 'Lecithin is a natural surfactant found in egg yolks.', example_ko_3 = '레시틴은 달걀 노른자에서 발견되는 천연 계면활성제예요.', example_en_4 = 'He explained that soap works because it is a surfactant.', example_ko_4 = '그는 비누가 계면활성제이기 때문에 효과가 있다고 설명했어요.', example_en_5 = 'Understanding surfactant properties is important in emulsion-based cooking.', example_ko_5 = '계면활성제 특성을 이해하는 것은 에멀션 기반 요리에서 중요해요.' WHERE id = 'w_cooking_C2_15';

UPDATE words SET example_en_2 = 'She uses hydrocolloid gels to create unique textures in her desserts.', example_ko_2 = '그녀는 디저트에 독특한 식감을 만들기 위해 하이드로콜로이드 겔을 사용해요.', example_en_3 = 'Agar and carrageenan are common hydrocolloids in food science.', example_ko_3 = '한천과 카라기난은 식품 과학에서 흔히 사용되는 하이드로콜로이드예요.', example_en_4 = 'He studied the properties of each hydrocolloid before choosing one for his recipe.', example_ko_4 = '그는 레시피에 사용할 하이드로콜로이드를 선택하기 전에 각 특성을 연구했어요.', example_en_5 = 'Hydrocolloids are used in food to control texture and stabilise products.', example_ko_5 = '하이드로콜로이드는 식품에서 식감을 조절하고 제품을 안정시키는 데 사용돼요.' WHERE id = 'w_cooking_C2_16';

UPDATE words SET example_en_2 = 'She studied the rheology of doughs to understand gluten development.', example_ko_2 = '그녀는 글루텐 발달을 이해하기 위해 반죽의 유변학을 공부했어요.', example_en_3 = 'Rheology helps explain why some sauces flow easily and others do not.', example_ko_3 = '유변학은 일부 소스는 쉽게 흐르고 다른 것은 그렇지 않은 이유를 설명해요.', example_en_4 = 'He applied rheology principles to improve the texture of his new noodle product.', example_ko_4 = '그는 새 국수 제품의 식감을 개선하기 위해 유변학 원리를 적용했어요.', example_en_5 = 'Rheology is an important field where physics meets food science.', example_ko_5 = '유변학은 물리학과 식품 과학이 만나는 중요한 분야예요.' WHERE id = 'w_cooking_C2_17';

UPDATE words SET example_en_2 = 'She measured the viscosity of the sauce to ensure consistent quality.', example_ko_2 = '그녀는 일정한 품질을 보장하기 위해 소스의 점도를 측정했어요.', example_en_3 = 'High viscosity means a liquid is thick and flows slowly.', example_ko_3 = '점도가 높다는 것은 액체가 진하고 천천히 흐른다는 뜻이에요.', example_en_4 = 'He adjusted the viscosity of the glaze by adding more corn syrup.', example_ko_4 = '그는 옥수수 시럽을 더 넣어 글레이즈의 점도를 조절했어요.', example_en_5 = 'Temperature has a big effect on the viscosity of cooking oils.', example_ko_5 = '온도는 식용 오일의 점도에 큰 영향을 미쳐요.' WHERE id = 'w_cooking_C2_18';

UPDATE words SET example_en_2 = 'She could detect the sensory threshold of bitterness in coffee very accurately.', example_ko_2 = '그녀는 커피의 쓴맛 감각 역치를 매우 정확하게 감지할 수 있었어요.', example_en_3 = 'The sensory threshold for sweetness varies between individuals.', example_ko_3 = '단맛의 감각 역치는 개인마다 달라요.', example_en_4 = 'He studies how processing affects the sensory threshold of salt.', example_ko_4 = '그는 가공이 소금의 감각 역치에 어떤 영향을 미치는지 연구해요.', example_en_5 = 'Understanding sensory thresholds helps food scientists design better products.', example_ko_5 = '감각 역치를 이해하면 식품 과학자들이 더 좋은 제품을 설계하는 데 도움이 돼요.' WHERE id = 'w_cooking_C2_19';

UPDATE words SET example_en_2 = 'She studied how olfactory receptors distinguish between thousands of aromas.', example_ko_2 = '그녀는 후각 수용체가 수천 가지 향을 어떻게 구별하는지 연구했어요.', example_en_3 = 'Olfactory receptors send signals directly to the brain''s memory centres.', example_ko_3 = '후각 수용체는 뇌의 기억 중추로 직접 신호를 보내요.', example_en_4 = 'He explained how olfactory receptors can detect volatiles in parts per trillion.', example_ko_4 = '그는 후각 수용체가 조 분의 1 단위로 휘발성 물질을 감지하는 방법을 설명했어요.', example_en_5 = 'Training your olfactory receptors is key to becoming a skilled taster.', example_ko_5 = '후각 수용체를 훈련하는 것이 숙련된 테이스터가 되는 핵심이에요.' WHERE id = 'w_cooking_C2_20';

UPDATE words SET example_en_2 = 'She studied how gustatory pathways process taste information in the brain.', example_ko_2 = '그녀는 미각 경로가 뇌에서 어떻게 미각 정보를 처리하는지 연구했어요.', example_en_3 = 'Gustatory perception involves both taste receptor cells and nerve signals.', example_ko_3 = '미각 지각에는 미각 수용체 세포와 신경 신호 모두 관여해요.', example_en_4 = 'He described gustatory sensation as deeply connected to memory and emotion.', example_ko_4 = '그는 미각 감각이 기억과 감정에 깊이 연결되어 있다고 표현했어요.', example_en_5 = 'Gustatory experience is enhanced when combined with olfactory input.', example_ko_5 = '미각 경험은 후각 자극과 결합할 때 향상돼요.' WHERE id = 'w_cooking_C2_21';

UPDATE words SET example_en_2 = 'She used retronasal olfaction to evaluate the finish of the wine.', example_ko_2 = '그녀는 와인의 여운을 평가하기 위해 후비강 후각을 사용했어요.', example_en_3 = 'Retronasal olfaction occurs when aromas travel up from the throat to the nose.', example_ko_3 = '후비강 후각은 향이 목구멍에서 코로 올라올 때 발생해요.', example_en_4 = 'He explained that most of what we call "taste" is actually retronasal olfaction.', example_ko_4 = '그는 우리가 "맛"이라고 부르는 것의 대부분이 실제로는 후비강 후각이라고 설명했어요.', example_en_5 = 'Retronasal olfaction is why food tastes bland when you have a cold.', example_ko_5 = '후비강 후각이 감기에 걸리면 음식이 싱겁게 느껴지는 이유예요.' WHERE id = 'w_cooking_C2_22';

UPDATE words SET example_en_2 = 'She studied flavor perception to understand why people prefer certain foods.', example_ko_2 = '그녀는 사람들이 특정 음식을 왜 선호하는지 이해하기 위해 풍미 지각을 공부했어요.', example_en_3 = 'Flavor perception is strongly shaped by cultural background and upbringing.', example_ko_3 = '풍미 지각은 문화적 배경과 성장 환경에 의해 강하게 형성돼요.', example_en_4 = 'He researched how aging affects flavor perception in older adults.', example_ko_4 = '그는 노화가 노인의 풍미 지각에 어떻게 영향을 미치는지 연구했어요.', example_en_5 = 'Flavor perception involves all five senses working together.', example_ko_5 = '풍미 지각에는 다섯 가지 감각이 모두 함께 작용해요.' WHERE id = 'w_cooking_C2_23';

UPDATE words SET example_en_2 = 'She sources wine for the restaurant based on the terroir of each region.', example_ko_2 = '그녀는 각 지역의 테루아를 바탕으로 레스토랑 와인을 조달해요.', example_en_3 = 'Terroir explains why the same grape variety can taste so different.', example_ko_3 = '테루아가 같은 포도 품종이 왜 이렇게 다른 맛을 낼 수 있는지 설명해요.', example_en_4 = 'He firmly believes that terroir is the soul of great wine and cheese.', example_ko_4 = '그는 테루아가 훌륭한 와인과 치즈의 영혼이라고 굳게 믿어요.', example_en_5 = 'The concept of terroir is now applied beyond wine to olive oil and coffee.', example_ko_5 = '테루아의 개념은 이제 와인을 넘어 올리브 오일과 커피에도 적용돼요.' WHERE id = 'w_cooking_C2_24';

UPDATE words SET example_en_2 = 'She researches the provenance of heritage grain varieties.', example_ko_2 = '그녀는 전통 곡물 품종의 원산지를 연구해요.', example_en_3 = 'Provenance labelling builds trust between producers and consumers.', example_ko_3 = '원산지 표시는 생산자와 소비자 사이에 신뢰를 쌓아요.', example_en_4 = 'He traced the provenance of the cheese to a specific farm in the Alps.', example_ko_4 = '그는 치즈의 원산지를 알프스의 특정 농장까지 추적했어요.', example_en_5 = 'Clear provenance information helps consumers make informed food choices.', example_ko_5 = '명확한 원산지 정보는 소비자가 정보에 기반한 식품 선택을 하는 데 도움을 줘요.' WHERE id = 'w_cooking_C2_25';

UPDATE words SET example_en_2 = 'She wrote her thesis on the role of indigenous ingredients in national identity.', example_ko_2 = '그녀는 국가 정체성에서 토착 재료의 역할에 관한 논문을 썼어요.', example_en_3 = 'Indigenous ingredients are increasingly celebrated by top chefs worldwide.', example_ko_3 = '토착 재료는 전 세계 유명 요리사들에 의해 점점 더 주목받고 있어요.', example_en_4 = 'He focuses his cooking on reviving forgotten indigenous ingredients.', example_ko_4 = '그는 잊혀진 토착 재료를 부활시키는 데 요리를 집중해요.', example_en_5 = 'Using indigenous ingredients supports local biodiversity and culture.', example_ko_5 = '토착 재료를 사용하면 지역 생물 다양성과 문화를 지원해요.' WHERE id = 'w_cooking_C2_26';

UPDATE words SET example_en_2 = 'She advocates for food sovereignty as a core principle of sustainable food systems.', example_ko_2 = '그녀는 지속 가능한 식품 시스템의 핵심 원칙으로 식량 주권을 지지해요.', example_en_3 = 'Food sovereignty empowers communities to decide what they grow and eat.', example_ko_3 = '식량 주권은 지역 사회가 무엇을 재배하고 먹을지 결정할 권한을 줘요.', example_en_4 = 'He wrote about food sovereignty and its links to cultural heritage.', example_ko_4 = '그는 식량 주권과 문화적 유산과의 연관성에 대해 글을 썼어요.', example_en_5 = 'The food sovereignty movement challenges industrial food systems.', example_ko_5 = '식량 주권 운동은 산업적 식품 시스템에 도전해요.' WHERE id = 'w_cooking_C2_27';

UPDATE words SET example_en_2 = 'She explores culinary anthropology through fieldwork in Southeast Asia.', example_ko_2 = '그녀는 동남아시아 현장 조사를 통해 요리 인류학을 탐구해요.', example_en_3 = 'Culinary anthropology examines the social and cultural meanings of food.', example_ko_3 = '요리 인류학은 음식의 사회적, 문화적 의미를 탐구해요.', example_en_4 = 'He teaches culinary anthropology at a food studies university.', example_ko_4 = '그는 식품 연구 대학에서 요리 인류학을 가르쳐요.', example_en_5 = 'Culinary anthropology helps us understand why food rituals matter.', example_ko_5 = '요리 인류학은 왜 음식 의식이 중요한지 이해하는 데 도움을 줘요.' WHERE id = 'w_cooking_C2_28';

UPDATE words SET example_en_2 = 'She is dedicated to preserving gastronomic heritage for future generations.', example_ko_2 = '그녀는 미래 세대를 위해 미식 유산을 보존하는 데 헌신해요.', example_en_3 = 'UNESCO recognises certain cuisines as part of gastronomic heritage.', example_ko_3 = 'UNESCO는 특정 음식 문화를 미식 유산의 일부로 인정해요.', example_en_4 = 'He documents traditional recipes as part of gastronomic heritage research.', example_ko_4 = '그는 미식 유산 연구의 일환으로 전통 조리법을 기록해요.', example_en_5 = 'Gastronomic heritage reflects the history and values of a community.', example_ko_5 = '미식 유산은 한 공동체의 역사와 가치를 반영해요.' WHERE id = 'w_cooking_C2_29';

UPDATE words SET example_en_2 = 'She uses nutritional epidemiology to study the link between diet and disease.', example_ko_2 = '그녀는 식단과 질병의 연관성을 연구하기 위해 영양 역학을 사용해요.', example_en_3 = 'Nutritional epidemiology relies on large population studies.', example_ko_3 = '영양 역학은 대규모 인구 연구에 의존해요.', example_en_4 = 'He critiqued the limitations of nutritional epidemiology in a journal article.', example_ko_4 = '그는 학술지 논문에서 영양 역학의 한계를 비판했어요.', example_en_5 = 'Nutritional epidemiology has shaped official dietary guidelines worldwide.', example_ko_5 = '영양 역학은 전 세계 공식 식이 지침을 형성하는 데 기여했어요.' WHERE id = 'w_cooking_C2_30';

UPDATE words SET example_en_2 = 'She analyses dietary patterns to identify links to long-term health outcomes.', example_ko_2 = '그녀는 장기적 건강 결과와의 연관성을 파악하기 위해 식이 패턴을 분석해요.', example_en_3 = 'Dietary patterns in Mediterranean regions are associated with longevity.', example_ko_3 = '지중해 지역의 식이 패턴은 장수와 관련이 있어요.', example_en_4 = 'He changed his dietary patterns after learning about nutritional science.', example_ko_4 = '그는 영양 과학을 배운 후 식이 패턴을 바꿨어요.', example_en_5 = 'Plant-based dietary patterns have been linked to reduced disease risk.', example_ko_5 = '식물성 식이 패턴은 질병 위험 감소와 관련이 있어요.' WHERE id = 'w_cooking_C2_31';

UPDATE words SET example_en_2 = 'She researches sustainable food systems at a food policy institute.', example_ko_2 = '그녀는 식품 정책 연구소에서 지속 가능한 식품 시스템을 연구해요.', example_en_3 = 'Transforming food systems is essential to addressing climate change.', example_ko_3 = '식품 시스템을 변화시키는 것은 기후 변화에 대응하는 데 필수예요.', example_en_4 = 'He advocates for more equitable food systems in developing countries.', example_ko_4 = '그는 개발 도상국에서 더 공평한 식품 시스템을 지지해요.', example_en_5 = 'Food systems research connects agriculture, nutrition, and public health.', example_ko_5 = '식품 시스템 연구는 농업, 영양, 공중 보건을 연결해요.' WHERE id = 'w_cooking_C2_32';

UPDATE words SET example_en_2 = 'She works to protect agrobiodiversity by cataloguing heritage seed varieties.', example_ko_2 = '그녀는 전통 씨앗 품종을 목록화함으로써 농업 생물 다양성을 보호하기 위해 노력해요.', example_en_3 = 'Agrobiodiversity is crucial for food security and resilient food systems.', example_ko_3 = '농업 생물 다양성은 식량 안보와 회복력 있는 식품 시스템에 중요해요.', example_en_4 = 'He argues that modern agriculture has severely reduced agrobiodiversity.', example_ko_4 = '그는 현대 농업이 농업 생물 다양성을 심각하게 감소시켰다고 주장해요.', example_en_5 = 'Agrobiodiversity includes not just plants but also animals and microorganisms.', example_ko_5 = '농업 생물 다양성에는 식물뿐만 아니라 동물과 미생물도 포함돼요.' WHERE id = 'w_cooking_C2_33';

UPDATE words SET example_en_2 = 'She applies culinary semiotics to analyse how food is represented in media.', example_ko_2 = '그녀는 요리 기호학을 적용해 미디어에서 음식이 어떻게 표현되는지 분석해요.', example_en_3 = 'Culinary semiotics examines the meanings embedded in food choices and rituals.', example_ko_3 = '요리 기호학은 음식 선택과 의식에 내재된 의미를 탐구해요.', example_en_4 = 'He wrote a chapter on culinary semiotics for a food culture anthology.', example_ko_4 = '그는 음식 문화 선집을 위해 요리 기호학에 관한 장을 썼어요.', example_en_5 = 'Culinary semiotics helps explain why certain foods symbolise celebration.', example_ko_5 = '요리 기호학은 왜 특정 음식이 축하를 상징하는지 설명하는 데 도움을 줘요.' WHERE id = 'w_cooking_C2_34';

UPDATE words SET example_en_2 = 'She studies how cooking techniques have shaped culinary semiotics over centuries.', example_ko_2 = '그녀는 요리 기법이 수 세기에 걸쳐 요리 기호학을 어떻게 형성해 왔는지 연구해요.', example_en_3 = 'Her dissertation linked culinary tradition to cultural identity through food semiotics.', example_ko_3 = '그녀의 논문은 음식 기호학을 통해 요리 전통과 문화적 정체성을 연결했어요.', example_en_4 = 'He attended a seminar on the intersection of gastronomy and cultural theory.', example_ko_4 = '그는 미식학과 문화 이론의 교차점에 관한 세미나에 참석했어요.', example_en_5 = 'Food as a cultural sign carries meaning far beyond mere nutrition.', example_ko_5 = '문화적 기호로서의 음식은 단순한 영양을 훨씬 넘어서는 의미를 담고 있어요.' WHERE id = 'w_cooking_C2_35';

